   153→    if (strcmp(method, "POST") == 0 && *upload_data_size > 0) {
   154→        post_ctx_t *pctx = *con_cls;
   155→        if (pctx->size + *upload_data_size > MAX_PAYLOAD_SIZE) {
   156→            http_text_reply(connection, RESP_BAD_REQUEST,
