   161→        if (post_ctx_append(pctx, upload_data, *upload_data_size) < 0) {
   162→            http_text_reply(connection, RESP_SERVER_ERR,
   163→                            "Internal buffer allocation failure");
   164→            return MHD_YES;
   165→        }
   166→
   167→        *upload_data_size = 0; /* signal libmicrohttpd we've consumed chunk */
   168→        return MHD_YES;
   169→    }
