   204→/**
   205→ * GET /v1/artifacts/{uuid}
   206→ */
   207→static int
   208→handle_get_artifact(struct MHD_Connection *connection,
   209→                    const char *artifact_id)
   210→{
   211→    if (!validate_uuid(artifact_id))
   212→        return http_text_reply(connection, RESP_BAD_REQUEST,
