   225→/**
   226→ * POST /v1/bids
   227→ * Body:
   228→ *   {
   229→ *     "artifact_id": "<uuid>",
   230→ *     "amount"     : <uint64>,    (wei)
   231→ *     "bidder"     : "<wallet-addr-hex>"
   232→ *   }
   233→ */
   234→static int
   235→handle_post_bid(gateway_ctx_t *gw_ctx,
   236→                struct MHD_Connection *connection,
   237→                post_ctx_t *post_ctx)
   238→{
   239→    json_error_t jerr;
   240→    json_t *root = json_loads(post_ctx->payload, JSON_DECODE_ANY, &jerr);
   241→    if (!root) {
   242→        return http_text_reply(connection, RESP_BAD_REQUEST,
   243→                               "Malformed JSON body");
   244→    }
   245→
   246→    const char *artifact_id = json_string_value(json_object_get(root, "artifact_id"));
   247→    const char *bidder      = json_string_value(json_object_get(root, "bidder"));
   248→    json_t *amount_node     = json_object_get(root, "amount");
   249→
   250→    if (!artifact_id || !bidder || !amount_node ||
   251→        !json_is_string(amount_node) && !json_is_integer(amount_node)) {
   252→        json_decref(root);
   253→        return http_text_reply(connection, RESP_BAD_REQUEST,
   254→                               "Missing or invalid fields");
   255→    }
   256→
   257→    if (!validate_uuid(artifact_id)) {
   258→        json_decref(root);
   259→        return http_text_reply(connection, RESP_BAD_REQUEST,
   260→                               "Invalid artifact_id");
   261→    }
   262→
   263→    uint64_t amount = 0;
   264→    if (json_is_integer(amount_node)) {
   265→        amount = (uint64_t)json_integer_value(amount_node);
   266→    } else { /* string – parse uint64 */
   267→        const char *s = json_string_value(amount_node);
   268→        if (!s || sscanf(s, "%" SCNu64, &amount) != 1) {
   269→            json_decref(root);
   270→            return http_text_reply(connection, RESP_BAD_REQUEST,
   271→                                   "Invalid amount");
   272→        }
   273→    }
   274→
   275→    /* Check artifact existence */
   276→    if (!artifact_repo_exists(artifact_id)) {
   277→        json_decref(root);
   278→        return http_text_reply(connection, RESP_NOT_FOUND,
   279→                               "Artifact not found");
   280→    }
   281→
   282→    /* Publish bid event to Kafka */
   283→    json_t *event = json_pack("{s:s, s:s, s:I}",
   284→                              "artifact_id", artifact_id,
   285→                              "bidder",      bidder,
   286→                              "amount",      amount);
   287→    char *event_str = json_dumps(event, JSON_COMPACT);
   288→    rd_kafka_resp_err_t kerr =
   289→        event_bus_produce(gw_ctx->rk, gw_ctx->topic, event_str, strlen(event_str));
   290→    json_decref(event);
   291→    free(event_str);
   292→
   293→    if (kerr != RD_KAFKA_RESP_ERR_NO_ERROR) {
   294→        json_decref(root);
   295→        return http_text_reply(connection, RESP_SERVER_ERR,
   296→                               "Failed to publish bid event");
   297→    }
   298→
   299→    json_decref(root);
   300→    return http_text_reply(connection, RESP_OK,
   301→                           "Bid received");
   302→}
