   306→static int
   307→http_json_reply(struct MHD_Connection *connection,
   308→                unsigned int status_code,
   309→                json_t *body)
   310→{
   311→    char *dump = json_dumps(body, JSON_INDENT | JSON_ENSURE_ASCII);
   312→    struct MHD_Response *resp = MHD_create_response_from_buffer(
   313→        strlen(dump), (void *)dump, MHD_RESPMEM_MUST_FREE);
   314→    if (!resp) { free(dump); return MHD_NO; }
   315→
   316→    MHD_add_response_header(resp, "Content-Type", "application/json");
   317→    int ret = MHD_queue_response(connection, status_code, resp);
   318→    MHD_destroy_response(resp);
   319→    return ret;
   320→}
   321→
   322→static int
   323→http_text_reply(struct MHD_Connection *connection,
   324→                unsigned int status_code,
   325→                const char *msg)
   326→{
   327→    struct MHD_Response *resp = MHD_create_response_from_buffer(
   328→        strlen(msg), (void *)msg, MHD_RESPMEM_PERSISTENT);
   329→    if (!resp) return MHD_NO;
   330→
   331→    MHD_add_response_header(resp, "Content-Type", "text/plain; charset=utf-8");
   332→    int ret = MHD_queue_response(connection, status_code, resp);
   333→    MHD_destroy_response(resp);
   334→    return ret;
   335→}
