   337→/**
   338→ * Validate UUID v4 string (basic check, 36 chars + pattern)
   339→ */
   340→static int
   341→validate_uuid(const char *uuid_str)
   342→{
   343→    if (!uuid_str || strlen(uuid_str) != 36) return 0;
   344→    uuid_t uu;
   345→    return (uuid_parse(uuid_str, uu) == 0);
   346→}
