   348→/* ------------- Public API ---------------------------------------------- */
   349→
   350→gateway_ctx_t *
   351→gateway_start(void)
   352→{
   353→    gateway_ctx_t *ctx = calloc(1, sizeof(*ctx));
   354→    if (!ctx) {
   355→        fprintf(stderr, "Failed to alloc gateway context\n");
   356→        return NULL;
   357→    }
   358→
   359→    /* -------- Event-Bus (Kafka) -------------------------------------- */
   360→    ctx->rk = event_bus_create_producer(CONFIG_KAFKA_BROKERS);
   361→    if (!ctx->rk) {
   362→        fprintf(stderr, "Kafka producer init failed\n");
   363→        free(ctx);
   364→        return NULL;
   365→    }
   366→    ctx->topic = rd_kafka_topic_new(ctx->rk,
   367→                                    CONFIG_KAFKA_TOPIC_EVENTS,
   368→                                    NULL);
   369→    if (!ctx->topic) {
   370→        fprintf(stderr, "Failed to create Kafka topic handle\n");
   371→        rd_kafka_destroy(ctx->rk);
   372→        free(ctx);
   373→        return NULL;
   374→    }
   375→
   376→    /* -------- HTTP Server (libmicrohttpd) ---------------------------- */
   377→    ctx->daemon = MHD_start_daemon(
   378→        MHD_USE_AUTO_INTERNAL_THREAD | MHD_USE_SELECT_INTERNALLY,
   379→        HTTP_PORT,
   380→        NULL, NULL,                      /* accept policy: default */
   381→        &router_handler, ctx,            /* request handler + arg  */
   382→        MHD_OPTION_CONNECTION_TIMEOUT, 10,
   383→        MHD_OPTION_END);
   384→
   385→    if (!ctx->daemon) {
   386→        fprintf(stderr, "microhttpd failed on port %d\n", HTTP_PORT);
   387→        rd_kafka_topic_destroy(ctx->topic);
   388→        rd_kafka_destroy(ctx->rk);
   389→        free(ctx);
   390→        return NULL;
   391→    }
   392→
   393→    printf("[Gateway] HTTP server started on port %d\n", HTTP_PORT);
   394→    return ctx;
   395→}
   396→
   397→void
   398→gateway_stop(gateway_ctx_t *ctx)
   399→{
   400→    if (!ctx) return;
   401→
   402→    MHD_stop_daemon(ctx->daemon);
   403→    rd_kafka_flush(ctx->rk, 5000);            /* ensure all messages sent */
   404→    rd_kafka_topic_destroy(ctx->topic);
   405→    rd_kafka_destroy(ctx->rk);
   406→    free(ctx);
   407→
   408→    printf("[Gateway] Clean shutdown complete\n");
   409→}
   410→
   411→/* ------------- Main (for standalone debug) ----------------------------- */
   412→
   413→#ifdef DEBUG_GATEWAY
   414→int
   415→main(void)
   416→{
   417→    gateway_ctx_t *gw = gateway_start();
   418→    if (!gw) return EXIT_FAILURE;
   419→
   420→    printf("Press ENTER to quit...\n");
   421→    getchar();
   422→
   423→    gateway_stop(gw);
   424→    return EXIT_SUCCESS;
   425→}
   426→#endif
