    50→/* ────────────────────────────────────────────────────────────────────────── */
    51→/* Internal structures                                                      */
    52→/* ────────────────────────────────────────────────────────────────────────── */
    53→
    54→/* Processing statistics (hot in write-path, kept in memory) */
    55→typedef struct txp_stats_s
    56→{
    57→    uint64_t accepted;
    58→    uint64_t rejected_sig;
    59→    uint64_t rejected_nonce;
    60→    uint64_t rejected_balance;
    61→    uint64_t rejected_payload;
    62→} txp_stats_t;
    63→
    64→/*
    65→ * Transaction Processor context.
    66→ * One instance per LedgerCore node – shared across worker threads.
    67→ */
    68→typedef struct txp_ctx_s
    69→{
    70→    ledger_t       *ledger;
    71→    event_bus_t    *bus;
    72→    txp_stats_t     stats;
    73→    metrics_handle_t m_metrics;     /* Prometheus/OpenTelemetry handle       */
    74→    pthread_mutex_t mtx;            /* protects ledger & stats during write  */
    75→} txp_ctx_t;
    76→
    77→/* Forward declarations */
    78→static bool   tp_verify_signature(const tx_t *tx);
    79→static bool   tp_verify_nonce(txp_ctx_t *ctx, const tx_t *tx);
    80→static bool   tp_verify_funds(txp_ctx_t *ctx, const tx_t *tx);
    81→static int    tp_apply(txp_ctx_t *ctx, const tx_t *tx, uint64_t ts_unix);
    82→static void   tp_emit_event(txp_ctx_t *ctx, const tx_t *tx);
    83→static void   tp_record_metrics(txp_ctx_t *ctx, const char *label, uint64_t dur_ns);
