    89→/*
    90→ * tp_init()
    91→ *   Allocate and initialise a Transaction Processor context.
    92→ */
    93→txp_ctx_t *tp_init(ledger_t *ledger, event_bus_t *bus)
    94→{
    95→    if (!ledger || !bus) {
    96→        log_error("tp_init: invalid argument (ledger/bus)");
    97→        return NULL;
    98→    }
    99→
   100→    txp_ctx_t *ctx = calloc(1, sizeof(*ctx));
   101→    if (!ctx) {
   102→        log_error("tp_init: calloc failed (%s)", strerror(errno));
   103→        return NULL;
   104→    }
   105→
   106→    ctx->ledger = ledger;
   107→    ctx->bus    = bus;
   108→    pthread_mutex_init(&ctx->mtx, NULL);
   109→
   110→    /* Register metrics */
   111→    ctx->m_metrics = metrics_register_namespace("ledger_core_tx_processor");
   112→    if (ctx->m_metrics == METRICS_HANDLE_INVALID) {
   113→        log_error("tp_init: failed to register metrics namespace");
   114→        /* Continue; metrics are optional */
   115→    }
   116→
   117→    log_info("Transaction Processor initialised.");
   118→    return ctx;
   119→}
