   202→/* ────────────────────────────────────────────────────────────────────────── */
   203→/* Validation helpers                                                       */
   204→/* ────────────────────────────────────────────────────────────────────────── */
   205→
   206→/*
   207→ * Signature verification
   208→ */
   209→static bool tp_verify_signature(const tx_t *tx)
   210→{
   211→    if (!tx) return false;
   212→
   213→    /* Ed25519 public key & signature size are fixed (32 / 64 bytes) */
   214→    if (tx->sig_len != 64 || tx->pubkey_len != 32) {
   215→        log_debug("tp_verify_signature: malformed key/sig");
   216→        return false;
   217→    }
   218→
   219→    /* Hash the canonicalised, signature-free frame of the transaction */
   220→    uint8_t digest[32];
   221→    if (sha3_256(tx->frame, tx->frame_len, digest) != 0) {
   222→        log_error("tp_verify_signature: sha3_256 failed");
   223→        return false;
   224→    }
   225→
   226→    const bool ok = ed25519_verify(tx->signature, digest, sizeof(digest),
   227→                                   tx->pubkey);
   228→    if (!ok) {
   229→        log_debug("tp_verify_signature: invalid signature for tx %s", tx->tx_id);
   230→    }
   231→    return ok;
   232→}
   233→
   234→/*
   235→ * Nonce verification
   236→ *   Protects against replay and preserves causal order per-account.
   237→ */
   238→static bool tp_verify_nonce(txp_ctx_t *ctx, const tx_t *tx)
   239→{
   240→    account_state_t acct;
   241→    if (ledger_get_account_state(ctx->ledger, tx->from, &acct) != 0) {
   242→        log_debug("tp_verify_nonce: unknown account %s", tx->from);
   243→        return false; /* account must exist */
   244→    }
   245→
   246→    const bool ok = (tx->nonce == acct.next_nonce);
   247→    if (!ok) {
   248→        log_debug("tp_verify_nonce: expected nonce=%" PRIu64 ", got=%" PRIu64,
   249→                  acct.next_nonce, tx->nonce);
   250→    }
   251→    return ok;
   252→}
   253→
   254→/*
   255→ * Balance / funds verification
   256→ */
   257→static bool tp_verify_funds(txp_ctx_t *ctx, const tx_t *tx)
   258→{
   259→    account_state_t acct;
   260→    if (ledger_get_account_state(ctx->ledger, tx->from, &acct) != 0) {
   261→        return false;
   262→    }
   263→
   264→    /* Gas cost: base + payload-dependent */
   265→    const uint64_t gas_cost = tx->gas_price * tx->gas_limit;
   266→    const uint64_t total    = gas_cost + tx->value;
   267→
   268→    const bool ok = (acct.balance >= total);
   269→    if (!ok) {
   270→        log_debug("tp_verify_funds: balance %" PRIu64
   271→                  " < required %" PRIu64 " (gas=%" PRIu64 ", value=%" PRIu64 ")",
   272→                  acct.balance, total, gas_cost, tx->value);
   273→    }
   274→    return ok;
   275→}
   276→
   277→/* ────────────────────────────────────────────────────────────────────────── */
   278→/* Application / state-mutation                                             */
   279→/* ────────────────────────────────────────────────────────────────────────── */
   280→
   281→/*
   282→ * tp_apply()
   283→ *   Mutate ledger state and any domain-level state-machines.
   284→ *
   285→ *   NOTE: called inside the global mutex for now.  In production deployments
   286→ *   we may employ sharded, fine-grained locks or MVCC to improve throughput.
   287→ */
   288→static int tp_apply(txp_ctx_t *ctx, const tx_t *tx, uint64_t ts_unix)
   289→{
   290→    int rc = 0;
   291→
   292→    pthread_mutex_lock(&ctx->mtx);
   293→
   294→    /* Append ledger entry – durable write-ahead log (WAL) */
   295→    ledger_entry_t entry = {
   296→        .timestamp  = ts_unix,
   297→        .tx_id      = {0},
   298→        .raw        = tx->raw,
   299→        .raw_len    = tx->raw_len
   300→    };
   301→    memcpy(entry.tx_id, tx->tx_id, sizeof(entry.tx_id));
   302→
   303→    if ((rc = ledger_append(ctx->ledger, &entry)) != 0) {
   304→        log_error("tp_apply: ledger_append failed (rc=%d)", rc);
   305→        goto exit;
   306→    }
   307→
   308→    /* Update account nonce & balance */
   309→    if ((rc = ledger_inc_nonce(ctx->ledger, tx->from)) != 0) {
   310→        log_error("tp_apply: ledger_inc_nonce failed");
   311→        goto exit;
   312→    }
   313→    if ((rc = ledger_debit(ctx->ledger, tx->from,
   314→                           tx->value + (tx->gas_price * tx->gas_limit))) != 0) {
   315→        log_error("tp_apply: ledger_debit failed");
   316→        goto exit;
   317→    }
   318→    if (tx->value > 0 && tx->to[0] != '\0') {
   319→        if ((rc = ledger_credit(ctx->ledger, tx->to, tx->value)) != 0) {
   320→            log_error("tp_apply: ledger_credit failed");
   321→            goto exit;
   322→        }
   323→    }
   324→
   325→    /* Domain-specific: NFT state transitions, governance votes, etc. */
   326→    switch (tx->type) {
   327→        case TX_MINT_NFT:
   328→            rc = artifact_state_on_mint(ctx->ledger, &tx->payload.mint);
   329→            break;
   330→        case TX_TRANSFER_NFT:
   331→            rc = artifact_state_on_transfer(ctx->ledger, &tx->payload.transfer);
   332→            break;
   333→        case TX_GOVERNANCE_VOTE:
   334→            rc = governance_apply_vote(ctx->ledger, &tx->payload.vote);
   335→            break;
   336→        case TX_STATE_MACHINE_EVOLUTION:
   337→            rc = artifact_state_transition(ctx->ledger, &tx->payload.evolve);
   338→            break;
   339→        default:
   340→            /* For payment-only transactions nothing else to do */
   341→            break;
   342→    }
   343→
   344→    if (rc != 0) {
   345→        log_error("tp_apply: domain mutation failed (rc=%d)", rc);
   346→        /* TODO: roll-back ledger_write via undo-log once implemented */
   347→    }
   348→
   349→exit:
   350→    pthread_mutex_unlock(&ctx->mtx);
   351→    return rc;
   352→}
   353→
   354→/* ────────────────────────────────────────────────────────────────────────── */
   355→/* Event-Bus integration                                                    */
   356→/* ────────────────────────────────────────────────────────────────────────── */
   357→
   358→static void tp_emit_event(txp_ctx_t *ctx, const tx_t *tx)
   359→{
   360→    event_t ev = {
   361→        .topic = "ledger.tx.applied",
   362→        .ts_unix = (uint64_t)time(NULL)
   363→    };
   364→    snprintf(ev.key, sizeof(ev.key), "%s", tx->tx_id);
   365→
   366→    /* Copy raw transaction as payload; consumer services know how to decode */
   367→    ev.payload     = tx->raw;
   368→    ev.payload_len = tx->raw_len;
   369→
   370→    if (event_bus_publish(ctx->bus, &ev) != 0) {
   371→        log_error("tp_emit_event: failed to publish event for tx %s", tx->tx_id);
   372→    }
   373→}
   374→
   375→/* ────────────────────────────────────────────────────────────────────────── */
   376→/* Metrics                                                                  */
   377→/* ────────────────────────────────────────────────────────────────────────── */
   378→
   379→static void tp_record_metrics(txp_ctx_t *ctx, const char *label, uint64_t dur_ns)
   380→{
   381→    if (ctx->m_metrics == METRICS_HANDLE_INVALID) return;
   382→
   383→    metrics_counter_inc(ctx->m_metrics, "tx_total", label, 1);
   384→    metrics_histogram_observe(ctx->m_metrics, "tx_latency_ns", label, dur_ns);
   385→}
   386→
   387→/* ────────────────────────────────────────────────────────────────────────── */
   388→/* Debug/Introspection helpers                                              */
   389→/* ────────────────────────────────────────────────────────────────────────── */
   390→
   391→void tp_dump_stats(const txp_ctx_t *ctx, FILE *out)
   392→{
   393→    if (!ctx) return;
   394→    if (!out) out = stdout;
   395→
   396→    pthread_mutex_lock((pthread_mutex_t *)&ctx->mtx); /* cast away const */
   397→
   398→    fprintf(out,
   399→        "LedgerCore/TxProcessor stats:\n"
   400→        "  accepted          : %" PRIu64 "\n"
   401→        "  rejected_sig      : %" PRIu64 "\n"
   402→        "  rejected_nonce    : %" PRIu64 "\n"
   403→        "  rejected_balance  : %" PRIu64 "\n"
   404→        "  rejected_payload  : %" PRIu64 "\n",
   405→        ctx->stats.accepted,
   406→        ctx->stats.rejected_sig,
   407→        ctx->stats.rejected_nonce,
   408→        ctx->stats.rejected_balance,
   409→        ctx->stats.rejected_payload);
   410→
   411→    pthread_mutex_unlock((pthread_mutex_t *)&ctx->mtx);
   412→}
