   275→/* ------------------------------------------------------------------------- *
   276→ * Merkle tree                                                               *
   277→ * ------------------------------------------------------------------------- */
   278→
   279→static ledger_err_t
   280→compute_merkle_root(const tx_list_t *txs, hash256_t out_root)
   281→{
   282→    if (!txs || txs->count == 0) {
   283→        return LEDGER_EINVAL;
   284→    }
   285→
   286→    size_t leaf_count = txs->count;
   287→    size_t level_count = leaf_count;
   288→
   289→    /* Allocate working buffer – power of two rounding */
   290→    size_t capacity = 1;
   291→    while (capacity < leaf_count) capacity <<= 1;
   292→    hash256_t *buf = calloc(capacity, sizeof(hash256_t));
   293→    if (!buf) return LEDGER_ENOMEM;
   294→
   295→    /* Copy leaves (tx hashes) */
   296→    for (size_t i = 0; i < leaf_count; ++i) {
   297→        memcpy(buf[i], txs->items[i]->tx_hash, sizeof(hash256_t));
   298→    }
   299→    /* Pad duplicate of last leaf if odd count */
   300→    for (size_t i = leaf_count; i < capacity; ++i) {
   301→        memcpy(buf[i], buf[leaf_count - 1], sizeof(hash256_t));
   302→    }
   303→
   304→    /* Iteratively hash pairs */
   305→    hash256_t tmp;
   306→    while (level_count > 1) {
   307→        size_t next_level = (level_count + 1) / 2;
   308→        for (size_t i = 0, j = 0; i < level_count; i += 2, ++j) {
   309→            crypto_hash256_ctx hctx;
   310→            crypto_hash256_init(&hctx);
   311→            crypto_hash256_update(&hctx, buf[i],   sizeof(hash256_t));
   312→            crypto_hash256_update(&hctx, buf[i+1], sizeof(hash256_t));
   313→            crypto_hash256_final(&hctx, tmp);
   314→            memcpy(buf[j], tmp, sizeof(hash256_t));
   315→        }
   316→        level_count = next_level;
   317→    }
   318→
   319→    memcpy(out_root, buf[0], sizeof(hash256_t));
   320→    free(buf);
   321→    return LEDGER_OK;
   322→}
   323→
   324→/* ------------------------------------------------------------------------- *
   325→ * Utilities                                                                 *
   326→ * ------------------------------------------------------------------------- */
   327→
   328→static inline uint64_t
   329→unix_epoch_ms(void)
   330→{
   331→    struct timespec ts;
   332→    clock_gettime(CLOCK_REALTIME, &ts);
   333→    return (uint64_t)ts.tv_sec * 1000ULL + (uint64_t)(ts.tv_nsec / 1e6);
   334→}

