   115→/*
   116→ * evh_init – Initialise the event handler module and spawn the consumer
   117→ *            thread.  Returns 0 on success, <0 on fatal error.
   118→ */
   119→int evh_init(void)
   120→{
   121→    char errstr[512];
   122→
   123→    g_ctx.conf = rd_kafka_conf_new();
   124→    if (!g_ctx.conf)
   125→        return -ENOMEM;
   126→
   127→    /* Basic configuration */
   128→    if (rd_kafka_conf_set(g_ctx.conf, "bootstrap.servers",
   129→                          KAFKA_BROKERS, errstr, sizeof(errstr)) != RD_KAFKA_CONF_OK) {
   130→        log_error("Kafka conf error: %s", errstr);
   131→        return -EINVAL;
   132→    }
   133→
   134→    if (rd_kafka_conf_set(g_ctx.conf, "group.id",
   135→                          KAFKA_GROUP_ID, errstr, sizeof(errstr)) != RD_KAFKA_CONF_OK) {
   136→        log_error("Kafka conf error: %s", errstr);
   137→        return -EINVAL;
   138→    }
   139→
   140→    /* Handle rebalance callbacks if necessary
   141→     * rd_kafka_conf_set_rebalance_cb(g_ctx.conf, rebalance_cb); */
   142→
   143→    /* Create consumer instance */
   144→    g_ctx.rk = rd_kafka_new(RD_KAFKA_CONSUMER, g_ctx.conf, errstr, sizeof(errstr));
   145→    if (!g_ctx.rk) {
   146→        log_error("Failed to create Kafka consumer: %s", errstr);
   147→        return -ECANCELED;
   148→    }
   149→
   150→    /* Redirect Kafka logs to our logger */
   151→    rd_kafka_set_log_level(g_ctx.rk, LOG_INFO);
   152→
   153→    /* Subscribe to topics */
   154→    rd_kafka_topic_partition_list_t *topics = rd_kafka_topic_partition_list_new(1);
   155→    rd_kafka_topic_partition_list_add(topics, KAFKA_TOPICS, RD_KAFKA_PARTITION_UA);
   156→
   157→    if (rd_kafka_subscribe(g_ctx.rk, topics) != RD_KAFKA_RESP_ERR_NO_ERROR) {
   158→        log_error("Kafka subscription failed");
   159→        rd_kafka_topic_partition_list_destroy(topics);
   160→        return -EIO;
   161→    }
   162→    rd_kafka_topic_partition_list_destroy(topics);
   163→
   164→    /* Spawn consume loop */
   165→    g_ctx.running = true;
   166→    if (pthread_create(&g_ctx.thread, NULL, run_loop, NULL) != 0) {
   167→        log_error("Failed to create consumer thread");
   168→        return -errno;
   169→    }
   170→
   171→    log_info("event_handler initialised (brokers=%s, group=%s, topics=%s)",
   172→             KAFKA_BROKERS, KAFKA_GROUP_ID, KAFKA_TOPICS);
   173→    return 0;
   174→}
