   176→/*
   177→ * evh_shutdown – Graceful shutdown; joins the consumer thread and
   178→ *                cleans up resources.
   179→ */
   180→void evh_shutdown(void)
   181→{
   182→    if (!g_ctx.running)
   183→        return;
   184→
   185→    g_ctx.running = false;
   186→    pthread_join(g_ctx.thread, NULL);
   187→
   188→    rd_kafka_consumer_close(g_ctx.rk);
   189→    rd_kafka_destroy(g_ctx.rk);
   190→
   191→    log_info("event_handler shutdown complete "
   192→             "(processed=%" PRIu64 ", parse_errors=%" PRIu64 ", dispatch_errors=%" PRIu64 ")",
   193→             g_metrics.processed, g_metrics.parse_errors, g_metrics.dispatch_errors);
   194→}
