   196→/* ────────────────────────────────────────────────────────────────────────── *
   197→ * Internal Helpers
   198→ * ────────────────────────────────────────────────────────────────────────── */
   199→
   200→/* Thread entry point */
   201→static void *run_loop(void *arg)
   202→{
   203→    (void)arg;
   204→    while (g_ctx.running) {
   205→        rd_kafka_message_t *rkmsg =
   206→            rd_kafka_consumer_poll(g_ctx.rk, KAFKA_CONSUMER_POLL_TIMEOUT_MS);
   207→
   208→        if (!rkmsg)
   209→            continue; /* Poll timeout */
   210→
   211→        if (rkmsg->err) {
   212→            if (rkmsg->err == RD_KAFKA_RESP_ERR__PARTITION_EOF) {
   213→                /* Log at debug level; nothing to do */
   214→                rd_kafka_message_destroy(rkmsg);
   215→                continue;
   216→            }
   217→            log_warn("Kafka error: %s", rd_kafka_message_errstr(rkmsg));
   218→            rd_kafka_message_destroy(rkmsg);
   219→            continue;
   220→        }
   221→
   222→        /* Parse and dispatch */
   223→        event_t evt = {0};
   224→        if (!parse_event((char *)rkmsg->payload, rkmsg->len, &evt)) {
   225→            g_metrics.parse_errors++;
   226→            log_warn("Failed to parse event (topic=%s, offset=%ld)",
   227→                     rd_kafka_topic_name(rkmsg->rkt), rkmsg->offset);
   228→            /* Commit offset despite bad message to avoid poison-pill loops */
   229→            rd_kafka_commit_message(g_ctx.rk, rkmsg, 0);
   230→            rd_kafka_message_destroy(rkmsg);
   231→            continue;
   232→        }
   233→
   234→        if (dispatch_event(&evt) != 0) {
   235→            g_metrics.dispatch_errors++;
   236→            log_warn("Dispatch error for event ID %s (type=%d)", evt.id, evt.type);
   237→            /* Optionally implement retry or DLQ */
   238→        } else {
   239→            g_metrics.processed++;
   240→            metrics_inc_counter("evh_processed_total"); /* external metrics API */
   241→        }
   242→
   243→        free_event(&evt);
   244→        rd_kafka_commit_message(g_ctx.rk, rkmsg, 0);
   245→        rd_kafka_message_destroy(rkmsg);
   246→    }
   247→
   248→    return NULL;
   249→}
