   251→/*
   252→ * parse_event – Validate and normalise JSON message into event_t.
   253→ *
   254→ * Expected payload example:
   255→ * {
   256→ *   "id": "e7b84e46-8bc1-4ed4-ab04-7574c01234d2",
   257→ *   "type": "MINT_REQUEST",
   258→ *   "ts": 1695150687123,
   259→ *   "payload": { ... }
   260→ * }
   261→ */
   262→static bool parse_event(const char *json_str, size_t len, event_t *out_evt)
   263→{
   264→    bool ok = false;
   265→    json_error_t jerr;
   266→    json_t *root = json_loadb(json_str, len, 0, &jerr);
   267→    if (!root) {
   268→        log_debug("JSON parse error: %s (at line %d col %d)", jerr.text, jerr.line, jerr.column);
   269→        return false;
   270→    }
   271→
   272→    /* id */
   273→    const char *id = json_string_value(json_object_get(root, "id"));
   274→    if (!id || strlen(id) >= MAX_EVENT_ID_LEN) {
   275→        log_debug("Invalid or missing event id");
   276→        goto cleanup;
   277→    }
   278→    strncpy(out_evt->id, id, MAX_EVENT_ID_LEN);
   279→
   280→    /* type */
   281→    const char *type_str = json_string_value(json_object_get(root, "type"));
   282→    if (!type_str) {
   283→        log_debug("Event.type missing");
   284→        goto cleanup;
   285→    }
   286→
   287→    if      (strcmp(type_str, "MINT_REQUEST")     == 0) out_evt->type = EVT_MINT_REQUEST;
   288→    else if (strcmp(type_str, "BID")              == 0) out_evt->type = EVT_BID;
   289→    else if (strcmp(type_str, "GOVERNANCE_VOTE")  == 0) out_evt->type = EVT_GOVERNANCE_VOTE;
   290→    else if (strcmp(type_str, "ORACLE_FEED")      == 0) out_evt->type = EVT_ORACLE_FEED;
   291→    else out_evt->type = EVT_UNKNOWN;
   292→
   293→    /* timestamp */
   294→    json_t *ts_node = json_object_get(root, "ts");
   295→    if (!json_is_integer(ts_node)) {
   296→        log_debug("Event.ts missing or not integer");
   297→        goto cleanup;
   298→    }
   299→    out_evt->ts_epoch_ms = (uint64_t)json_integer_value(ts_node);
   300→
   301→    /* payload (keep raw to avoid extra serialise-deserialise cycles) */
   302→    json_t *payload_node = json_object_get(root, "payload");
   303→    if (!payload_node) {
   304→        log_debug("Event.payload missing");
   305→        goto cleanup;
   306→    }
   307→    /* Dump just the payload subtree for downstream modules */
   308→    out_evt->raw_payload = json_dumps(payload_node, JSON_COMPACT | JSON_ENSURE_ASCII);
   309→    if (!out_evt->raw_payload) {
   310→        log_debug("Failed to serialise payload subtree");
   311→        goto cleanup;
   312→    }
   313→
   314→    ok = true;
   315→
   316→cleanup:
   317→    json_decref(root);
   318→    return ok;
   319→}
