   328→/*
   329→ * dispatch_event – Call the appropriate domain handler.  Returns 0 on success.
   330→ */
   331→static int dispatch_event(const event_t *evt)
   332→{
   333→    int rc = 0;
   334→    char tsbuf[ISO_TS_BUF_SZ];
   335→    iso_timestamp(evt->ts_epoch_ms, tsbuf, sizeof(tsbuf));
   336→
   337→    switch (evt->type) {
   338→    case EVT_MINT_REQUEST:
   339→        log_info("Dispatching MINT_REQUEST id=%s ts=%s", evt->id, tsbuf);
   340→        rc = mint_engine_handle_request(evt->raw_payload);
   341→        break;
   342→
   343→    case EVT_BID:
   344→        log_info("Dispatching BID id=%s ts=%s", evt->id, tsbuf);
   345→        rc = mint_engine_handle_bid(evt->raw_payload);
   346→        break;
   347→
   348→    case EVT_GOVERNANCE_VOTE:
   349→        log_info("Dispatching GOVERNANCE_VOTE id=%s ts=%s", evt->id, tsbuf);
   350→        rc = mint_engine_handle_governance_vote(evt->raw_payload);
   351→        break;
   352→
   353→    case EVT_ORACLE_FEED:
   354→        log_info("Dispatching ORACLE_FEED id=%s ts=%s", evt->id, tsbuf);
   355→        rc = mint_engine_handle_oracle_feed(evt->raw_payload);
   356→        break;
   357→
   358→    default:
   359→        log_warn("Unknown event type (%d) id=%s", evt->type, evt->id);
   360→        rc = -EINVAL;
   361→        break;
   362→    }
   363→
   364→    return rc;
   365→}
