   380→/* ────────────────────────────────────────────────────────────────────────── *
   381→ * Signal Handling Convenience
   382→ * ────────────────────────────────────────────────────────────────────────── */
   383→
   384→static void sig_handler(int sig)
   385→{
   386→    (void)sig;
   387→    log_info("Received termination signal, shutting down");
   388→    evh_shutdown();
   389→    /* Exit entire process once clean-up completes */
   390→    _exit(EXIT_SUCCESS);
   391→}
