   393→/*
   394→ * evh_install_signal_handlers – Utility function that applications may call.
   395→ */
   396→void evh_install_signal_handlers(void)
   397→{
   398→    struct sigaction sa = {
   399→        .sa_handler = sig_handler,
   400→        .sa_flags   = 0
   401→    };
   402→    sigemptyset(&sa.sa_mask);
   403→    sigaction(SIGINT,  &sa, NULL);
   404→    sigaction(SIGTERM, &sa, NULL);
   405→}
