[metadata] {"type": "text", "file": {"filePath": "/app/project/services/mint_factory/src/event_handler.c", "content": "/*\n * HoloCanvas – Mint-Factory\n * File: event_handler.c\n *\n * Description:\n *   Event ingestion and dispatch layer for the Mint-Factory micro-service.\n *   Consumes domain events from the HoloCanvas Kafka mesh, parses the\n *   payloads (JSON/Protobuf), and routes them to the appropriate\n *   sub-systems (minting engine, bid processor, governance module, etc.).\n *\n *   This is intentionally self-contained so that unit-tests can stub\n *   external dependencies.  The production build links against\n *   -lrdkafka –ljansson –lpthread.\n *\n * Author: HoloCanvas Core Team\n * SPDX-License-Identifier: MIT\n */\n\n#include <errno.h>\n#include <inttypes.h>\n#include <signal.h>\n#include <stdarg.h>\n#include <stdbool.h>\n#include <stdint.h>\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n#include <time.h>\n#include <unistd.h>\n\n#include <jansson.h>\n#include <pthread.h>\n\n#include <rdkafka/rdkafka.h>\n\n#include \"event_handler.h\"  /* Local header (exports init/run/shutdown)    */\n#include \"metrics.h\"        /* Prometheus-style exporter (not in this file)*/\n#include \"mint_engine.h\"    /* Business logic for NFT minting             */\n#include \"logger.h\"         /* Syslog-style async logger                   */\n\n\n/* ────────────────────────────────────────────────────────────────────────── *\n * Compile-Time Configuration\n * ────────────────────────────────────────────────────────────────────────── */\n\n#ifndef KAFKA_BROKERS\n#define KAFKA_BROKERS       \"localhost:9092\"\n#endif\n\n#ifndef KAFKA_GROUP_ID\n#define KAFKA_GROUP_ID      \"mint_factory_consumer\"\n#endif\n\n#ifndef KAFKA_TOPICS\n#define KAFKA_TOPICS        \"mint-factory.events\"\n#endif\n\n#define KAFKA_CONSUMER_POLL_TIMEOUT_MS  250\n#define MAX_EVENT_ID_LEN                64\n#define ISO_TS_BUF_SZ                   32\n\n/* ────────────────────────────────────────────────────────────────────────── *\n * Local Data Structures\n * ────────────────────────────────────────────────────────────────────────── */\n\n/* Enumeration of canonical event types emitted onto the bus. */\ntypedef enum {\n    EVT_UNKNOWN = 0,\n    EVT_MINT_REQUEST,\n    EVT_BID,\n    EVT_GOVERNANCE_VOTE,\n    EVT_ORACLE_FEED\n} event_type_t;\n\n/* Generic event container. Additional type-specific fields live in\n * sub-structures that mint_engine.c and friends know how to decode. */\ntypedef struct {\n    event_type_t  type;\n    char          id[MAX_EVENT_ID_LEN];\n    uint64_t      ts_epoch_ms;\n    char         *raw_payload;   /* Original JSON string; ownership retained. */\n} event_t;\n\n/* ────────────────────────────────────────────────────────────────────────── *\n * Module State\n * ────────────────────────────────────────────────────────────────────────── */\n\ntypedef struct {\n    rd_kafka_t      *rk;          /* Kafka handle */\n    rd_kafka_conf_t *conf;        /* Kafka configuration */\n    bool             running;\n    pthread_t        thread;\n} evh_context_t;\n\nstatic evh_context_t g_ctx = {0};\n\n/* Metrics */\nstatic struct {\n    uint64_t processed;\n    uint64_t parse_errors;\n    uint64_t dispatch_errors;\n} g_metrics = {0};\n\n/* Forward declarations */\nstatic void *run_loop(void *arg);\nstatic bool parse_event(const char *json_str, size_t len, event_t *out_evt);\nstatic void free_event(event_t *evt);\nstatic int  dispatch_event(const event_t *evt);\nstatic char *iso_timestamp(uint64_t epoch_ms, char *buf, size_t buf_sz);\n\n/* ────────────────────────────────────────────────────────────────────────── *\n * Public API\n * ────────────────────────────────────────────────────────────────────────── */\n\n/*\n * evh_init – Initialise the event handler module and spawn the consumer\n *            thread.  Returns 0 on success, <0 on fatal error.\n */\nint evh_init(void)\n{\n    char errstr[512];\n\n    g_ctx.conf = rd_kafka_conf_new();\n    if (!g_ctx.conf)\n        return -ENOMEM;\n\n    /* Basic configuration */\n    if (rd_kafka_conf_set(g_ctx.conf, \"bootstrap.servers\",\n                          KAFKA_BROKERS, errstr, sizeof(errstr)) != RD_KAFKA_CONF_OK) {\n        log_error(\"Kafka conf error: %s\", errstr);\n        return -EINVAL;\n    }\n\n    if (rd_kafka_conf_set(g_ctx.conf, \"group.id\",\n                          KAFKA_GROUP_ID, errstr, sizeof(errstr)) != RD_KAFKA_CONF_OK) {\n        log_error(\"Kafka conf error: %s\", errstr);\n        return -EINVAL;\n    }\n\n    /* Handle rebalance callbacks if necessary\n     * rd_kafka_conf_set_rebalance_cb(g_ctx.conf, rebalance_cb); */\n\n    /* Create consumer instance */\n    g_ctx.rk = rd_kafka_new(RD_KAFKA_CONSUMER, g_ctx.conf, errstr, sizeof(errstr));\n    if (!g_ctx.rk) {\n        log_error(\"Failed to create Kafka consumer: %s\", errstr);\n        return -ECANCELED;\n    }\n\n    /* Redirect Kafka logs to our logger */\n    rd_kafka_set_log_level(g_ctx.rk, LOG_INFO);\n\n    /* Subscribe to topics */\n    rd_kafka_topic_partition_list_t *topics = rd_kafka_topic_partition_list_new(1);\n    rd_kafka_topic_partition_list_add(topics, KAFKA_TOPICS, RD_KAFKA_PARTITION_UA);\n\n    if (rd_kafka_subscribe(g_ctx.rk, topics) != RD_KAFKA_RESP_ERR_NO_ERROR) {\n        log_error(\"Kafka subscription failed\");\n        rd_kafka_topic_partition_list_destroy(topics);\n        return -EIO;\n    }\n    rd_kafka_topic_partition_list_destroy(topics);\n\n    /* Spawn consume loop */\n    g_ctx.running = true;\n    if (pthread_create(&g_ctx.thread, NULL, run_loop, NULL) != 0) {\n        log_error(\"Failed to create consumer thread\");\n        return -errno;\n    }\n\n    log_info(\"event_handler initialised (brokers=%s, group=%s, topics=%s)\",\n             KAFKA_BROKERS, KAFKA_GROUP_ID, KAFKA_TOPICS);\n    return 0;\n}\n\n/*\n * evh_shutdown – Graceful shutdown; joins the consumer thread and\n *                cleans up resources.\n */\nvoid evh_shutdown(void)\n{\n    if (!g_ctx.running)\n        return;\n\n    g_ctx.running = false;\n    pthread_join(g_ctx.thread, NULL);\n\n    rd_kafka_consumer_close(g_ctx.rk);\n    rd_kafka_destroy(g_ctx.rk);\n\n    log_info(\"event_handler shutdown complete \"\n             \"(processed=%\" PRIu64 \", parse_errors=%\" PRIu64 \", dispatch_errors=%\" PRIu64 \")\",\n             g_metrics.processed, g_metrics.parse_errors, g_metrics.dispatch_errors);\n}\n\n/* ────────────────────────────────────────────────────────────────────────── *\n * Internal Helpers\n * ────────────────────────────────────────────────────────────────────────── */\n\n/* Thread entry point */\nstatic void *run_loop(void *arg)\n{\n    (void)arg;\n    while (g_ctx.running) {\n        rd_kafka_message_t *rkmsg =\n            rd_kafka_consumer_poll(g_ctx.rk, KAFKA_CONSUMER_POLL_TIMEOUT_MS);\n\n        if (!rkmsg)\n            continue; /* Poll timeout */\n\n        if (rkmsg->err) {\n            if (rkmsg->err == RD_KAFKA_RESP_ERR__PARTITION_EOF) {\n                /* Log at debug level; nothing to do */\n                rd_kafka_message_destroy(rkmsg);\n                continue;\n            }\n            log_warn(\"Kafka error: %s\", rd_kafka_message_errstr(rkmsg));\n            rd_kafka_message_destroy(rkmsg);\n            continue;\n        }\n\n        /* Parse and dispatch */\n        event_t evt = {0};\n        if (!parse_event((char *)rkmsg->payload, rkmsg->len, &evt)) {\n            g_metrics.parse_errors++;\n            log_warn(\"Failed to parse event (topic=%s, offset=%ld)\",\n                     rd_kafka_topic_name(rkmsg->rkt), rkmsg->offset);\n            /* Commit offset despite bad message to avoid poison-pill loops */\n            rd_kafka_commit_message(g_ctx.rk, rkmsg, 0);\n            rd_kafka_message_destroy(rkmsg);\n            continue;\n        }\n\n        if (dispatch_event(&evt) != 0) {\n            g_metrics.dispatch_errors++;\n            log_warn(\"Dispatch error for event ID %s (type=%d)\", evt.id, evt.type);\n            /* Optionally implement retry or DLQ */\n        } else {\n            g_metrics.processed++;\n            metrics_inc_counter(\"evh_processed_total\"); /* external metrics API */\n        }\n\n        free_event(&evt);\n        rd_kafka_commit_message(g_ctx.rk, rkmsg, 0);\n        rd_kafka_message_destroy(rkmsg);\n    }\n\n    return NULL;\n}\n\n/*\n * parse_event – Validate and normalise JSON message into event_t.\n *\n * Expected payload example:\n * {\n *   \"id\": \"e7b84e46-8bc1-4ed4-ab04-7574c01234d2\",\n *   \"type\": \"MINT_REQUEST\",\n *   \"ts\": 1695150687123,\n *   \"payload\": { ... }\n * }\n */\nstatic bool parse_event(const char *json_str, size_t len, event_t *out_evt)\n{\n    bool ok = false;\n    json_error_t jerr;\n    json_t *root = json_loadb(json_str, len, 0, &jerr);\n    if (!root) {\n        log_debug(\"JSON parse error: %s (at line %d col %d)\", jerr.text, jerr.line, jerr.column);\n        return false;\n    }\n\n    /* id */\n    const char *id = json_string_value(json_object_get(root, \"id\"));\n    if (!id || strlen(id) >= MAX_EVENT_ID_LEN) {\n        log_debug(\"Invalid or missing event id\");\n        goto cleanup;\n    }\n    strncpy(out_evt->id, id, MAX_EVENT_ID_LEN);\n\n    /* type */\n    const char *type_str = json_string_value(json_object_get(root, \"type\"));\n    if (!type_str) {\n        log_debug(\"Event.type missing\");\n        goto cleanup;\n    }\n\n    if      (strcmp(type_str, \"MINT_REQUEST\")     == 0) out_evt->type = EVT_MINT_REQUEST;\n    else if (strcmp(type_str, \"BID\")              == 0) out_evt->type = EVT_BID;\n    else if (strcmp(type_str, \"GOVERNANCE_VOTE\")  == 0) out_evt->type = EVT_GOVERNANCE_VOTE;\n    else if (strcmp(type_str, \"ORACLE_FEED\")      == 0) out_evt->type = EVT_ORACLE_FEED;\n    else out_evt->type = EVT_UNKNOWN;\n\n    /* timestamp */\n    json_t *ts_node = json_object_get(root, \"ts\");\n    if (!json_is_integer(ts_node)) {\n        log_debug(\"Event.ts missing or not integer\");\n        goto cleanup;\n    }\n    out_evt->ts_epoch_ms = (uint64_t)json_integer_value(ts_node);\n\n    /* payload (keep raw to avoid extra serialise-deserialise cycles) */\n    json_t *payload_node = json_object_get(root, \"payload\");\n    if (!payload_node) {\n        log_debug(\"Event.payload missing\");\n        goto cleanup;\n    }\n    /* Dump just the payload subtree for downstream modules */\n    out_evt->raw_payload = json_dumps(payload_node, JSON_COMPACT | JSON_ENSURE_ASCII);\n    if (!out_evt->raw_payload) {\n        log_debug(\"Failed to serialise payload subtree\");\n        goto cleanup;\n    }\n\n    ok = true;\n\ncleanup:\n    json_decref(root);\n    return ok;\n}\n\nstatic void free_event(event_t *evt)\n{\n    if (evt->raw_payload)\n        free(evt->raw_payload);\n    memset(evt, 0, sizeof(*evt));\n}\n\n/*\n * dispatch_event – Call the appropriate domain handler.  Returns 0 on success.\n */\nstatic int dispatch_event(const event_t *evt)\n{\n    int rc = 0;\n    char tsbuf[ISO_TS_BUF_SZ];\n    iso_timestamp(evt->ts_epoch_ms, tsbuf, sizeof(tsbuf));\n\n    switch (evt->type) {\n    case EVT_MINT_REQUEST:\n        log_info(\"Dispatching MINT_REQUEST id=%s ts=%s\", evt->id, tsbuf);\n        rc = mint_engine_handle_request(evt->raw_payload);\n        break;\n\n    case EVT_BID:\n        log_info(\"Dispatching BID id=%s ts=%s\", evt->id, tsbuf);\n        rc = mint_engine_handle_bid(evt->raw_payload);\n        break;\n\n    case EVT_GOVERNANCE_VOTE:\n        log_info(\"Dispatching GOVERNANCE_VOTE id=%s ts=%s\", evt->id, tsbuf);\n        rc = mint_engine_handle_governance_vote(evt->raw_payload);\n        break;\n\n    case EVT_ORACLE_FEED:\n        log_info(\"Dispatching ORACLE_FEED id=%s ts=%s\", evt->id, tsbuf);\n        rc = mint_engine_handle_oracle_feed(evt->raw_payload);\n        break;\n\n    default:\n        log_warn(\"Unknown event type (%d) id=%s\", evt->type, evt->id);\n        rc = -EINVAL;\n        break;\n    }\n\n    return rc;\n}\n\n/*\n * iso_timestamp – Convert epoch_ms to ISO-8601 UTC string.\n */\nstatic char *iso_timestamp(uint64_t epoch_ms, char *buf, size_t buf_sz)\n{\n    time_t sec = (time_t)(epoch_ms / 1000ULL);\n    struct tm tm;\n    gmtime_r(&sec, &tm);\n    size_t n = strftime(buf, buf_sz, \"%Y-%m-%dT%H:%M:%S\", &tm);\n    snprintf(buf + n, buf_sz - n, \".%03\" PRIu64 \"Z\", epoch_ms % 1000ULL);\n    return buf;\n}\n\n/* ────────────────────────────────────────────────────────────────────────── *\n * Signal Handling Convenience\n * ────────────────────────────────────────────────────────────────────────── */\n\nstatic void sig_handler(int sig)\n{\n    (void)sig;\n    log_info(\"Received termination signal, shutting down\");\n    evh_shutdown();\n    /* Exit entire process once clean-up completes */\n    _exit(EXIT_SUCCESS);\n}\n\n/*\n * evh_install_signal_handlers – Utility function that applications may call.\n */\nvoid evh_install_signal_handlers(void)\n{\n    struct sigaction sa = {\n        .sa_handler = sig_handler,\n        .sa_flags   = 0\n    };\n    sigemptyset(&sa.sa_mask);\n    sigaction(SIGINT,  &sa, NULL);\n    sigaction(SIGTERM, &sa, NULL);\n}\n\n/* ────────────────────────────────────────────────────────────────────────── *\n * Unit-Test Hooks (weak linkage, allow overrides)\n * ────────────────────────────────────────────────────────────────────────── */\n\n__attribute__((weak))\nint mint_engine_handle_request(const char *payload_json) {\n    (void)payload_json; return 0;\n}\n\n__attribute__((weak))\nint mint_engine_handle_bid(const char *payload_json) {\n    (void)payload_json; return 0;\n}\n\n__attribute__((weak))\nint mint_engine_handle_governance_vote(const char *payload_json) {\n    (void)payload_json; return 0;\n}\n\n__attribute__((weak))\nint mint_engine_handle_oracle_feed(const char *payload_json) {\n    (void)payload_json; return 0;\n}\n\n/* End of file */", "numLines": 431, "startLine": 1, "totalLines": 431}}

1→/**
     2→ * HoloCanvas – Mint-Factory Microservice
     3→ * -------------------------------------
     4→ * artifact_factory.c
     5→ *
     6→ * Production-quality implementation of the Artifact Factory subsystem.  This unit
     7→ * is responsible for validating incoming recipe fragments, composing them into a
     8→ * canonical “creative recipe” JSON document, generating a deterministic SHA-256
     9→ * identifier, persisting the artifact to LedgerCore, and emitting the appropriate
    10→ * event onto the service event mesh.
    11→ *
    12→ * Author: HoloCanvas Core Team
    13→ * License: Apache-2.0
    14→ */
    15→
    16→#include <stdio.h>
    17→#include <stdlib.h>
    18→#include <stdbool.h>
    19→#include <stdint.h>
    20→#include <stdarg.h>
    21→#include <string.h>
    22→#include <time.h>
    23→#include <pthread.h>
    24→#include <errno.h>
    25→
    26→#include <openssl/sha.h>
    27→#include <cjson/cJSON.h>
    28→
    29→/*--- External service stubs (implemented elsewhere in the project) ----------*/
    30→#include "ledger_client.h"      /* LedgerCore L2 roll-up client                */
    31→#include "event_bus.h"          /* Kafka / gRPC event mesh abstraction         */
    32→#include "artifact_factory.h"   /* Public interface for this compilation unit  */
    33→#include "hc_logging.h"         /* Centralised logging facade                  */
    34→
    35→/*---------------------------------------------------------------------------*/
    36→/* Internal constants                                                        */
    37→/*---------------------------------------------------------------------------*/
    38→
    39→#define ARTIFACT_ID_HEX_SIZE (SHA256_DIGEST_LENGTH * 2 + 1)
    40→#define MAX_CREATOR_ADDR     96   /* Enough for bech32 or hex-encoded address */
    41→
    42→/*---------------------------------------------------------------------------*/
    43→/* Local data types                                                          */
    44→/*---------------------------------------------------------------------------*/
    45→
    46→/* Life-cycle states—the canonical definition sits in shared headers */
    47→typedef enum
    48→{
    49→    ART_STATE_DRAFT = 0,
    50→    ART_STATE_CURATED,
    51→    ART_STATE_AUCTION,
    52→    ART_STATE_FRACTIONALIZED,
    53→    ART_STATE_STAKED
    54→} artifact_state_e;
    55→
    56→/* A single creative recipe fragment set */
    57→typedef struct
    58→{
    59→    char *shader;    /* GLSL / WGSL fragment */
    60→    char *audio;     /* PureData │ Faust │ WebAudio Graph JSON */
    61→    char *metadata;  /* RFC 8259-compliant JSON */
    62→} artifact_fragments_t;
    63→
    64→/* Fully-fledged artifact object */
    65→typedef struct
    66→{
    67→    char                id[ARTIFACT_ID_HEX_SIZE];
    68→    artifact_fragments_t recipe;
    69→    char                creator[MAX_CREATOR_ADDR];
    70→    artifact_state_e    state;
    71→    time_t              created_at;
    72→} artifact_t;
    73→
    74→/* Factory-wide runtime state */
    75→typedef struct
    76→{
    77→    pthread_mutex_t lock;
    78→    bool            initialised;
    79→    /* ... future cache handles, metrics, etc. */
    80→} factory_ctx_t;
    81→
    82→/*---------------------------------------------------------------------------*/
    83→/* Static (translation-unit local) members                                   */
    84→/*---------------------------------------------------------------------------*/
    85→
    86→static factory_ctx_t g_ctx = {
    87→    .lock        = PTHREAD_MUTEX_INITIALIZER,
    88→    .initialised = false
    89→};
    90→
    91→/*---------------------------------------------------------------------------*/
    92→/* Forward declarations                                                      */
    93→/*---------------------------------------------------------------------------*/
    94→
    95→static bool validate_fragments(const artifact_fragments_t *fr);
    96→static cJSON *compose_recipe_json(const artifact_fragments_t *fr);
    97→static void   sha256_hex(const char *input, size_t len, char out_hex[ARTIFACT_ID_HEX_SIZE]);
    98→static bool   persist_to_ledger(const char *artifact_id, const char *recipe_json);
    99→static void   emit_event_artifact_minted(const artifact_t *artifact);
   100→
   101→/*---------------------------------------------------------------------------*/
   102→/* Public API implementation                                                 */
   103→/*---------------------------------------------------------------------------*/
   104→
   105→/**
   106→ * Initialise the Artifact Factory.  Must be called exactly once during
   107→ * service bootstrap.  Thread safe.
   108→ */
   109→af_status_e af_init(void)
   110→{
   111→    int rc;
   112→
   113→    pthread_mutex_lock(&g_ctx.lock);
   114→
   115→    if (g_ctx.initialised)
   116→    {
   117→        pthread_mutex_unlock(&g_ctx.lock);
   118→        return AF_STATUS_OK; /* Idempotent */
   119→    }
   120→
   121→    /* Initialise external subsystems */
   122→    if ((rc = ledger_client_init()) != 0)
   123→    {
   124→        HC_LOG_ERROR("artifact_factory: ledger_client_init() failed: %d", rc);
   125→        pthread_mutex_unlock(&g_ctx.lock);
   126→        return AF_STATUS_ERR_DEPENDENCY;
   127→    }
   128→
   129→    if ((rc = event_bus_init()) != 0)
   130→    {
   131→        HC_LOG_ERROR("artifact_factory: event_bus_init() failed: %d", rc);
   132→        pthread_mutex_unlock(&g_ctx.lock);
   133→        return AF_STATUS_ERR_DEPENDENCY;
   134→    }
   135→
   136→    g_ctx.initialised = true;
   137→    pthread_mutex_unlock(&g_ctx.lock);
   138→
   139→    HC_LOG_INFO("artifact_factory: initialised successfully");
   140→    return AF_STATUS_OK;
   141→}
   142→
   143→/**
   144→ * Tear down the Artifact Factory.
   145→ */
   146→void af_shutdown(void)
   147→{
   148→    pthread_mutex_lock(&g_ctx.lock);
   149→
   150→    if (!g_ctx.initialised)
   151→    {
   152→        pthread_mutex_unlock(&g_ctx.lock);
   153→        return;
   154→    }
   155→
   156→    ledger_client_shutdown();
   157→    event_bus_shutdown();
   158→
   159→    g_ctx.initialised = false;
   160→    pthread_mutex_unlock(&g_ctx.lock);
   161→    HC_LOG_INFO("artifact_factory: shutdown complete");
   162→}
   163→
   164→/**
   165→ * Mint a new generative artifact.  Ownership of dynamically allocated
   166→ * strings inside `fragments` is transferred to the factory on success.
   167→ *
   168→ * Parameters:
   169→ *  - fragments     : Pointer to caller-allocated fragment bundle
   170→ *  - creator_addr  : Null-terminated creator wallet address
   171→ *  - out_artifact_id (optional): Buffer receiving generated ID (hex-string)
   172→ *
   173→ * Returns:
   174→ *  AF_STATUS_OK on success, otherwise error code.
   175→ */
   176→af_status_e af_mint(const artifact_fragments_t *fragments,
   177→                    const char                 *creator_addr,
   178→                    char                       *out_artifact_id /* Nullable */)
   179→{
   180→    if (!g_ctx.initialised)
   181→    {
   182→        HC_LOG_ERROR("artifact_factory: must call af_init() first");
   183→        return AF_STATUS_ERR_NOT_INIT;
   184→    }
   185→
   186→    if (!fragments || !creator_addr)
   187→    {
   188→        HC_LOG_ERROR("artifact_factory: invalid argument (null ptr)");
   189→        return AF_STATUS_ERR_INVALID_ARG;
   190→    }
   191→
   192→    if (!validate_fragments(fragments))
   193→    {
   194→        HC_LOG_WARN("artifact_factory: fragment validation failed");
   195→        return AF_STATUS_ERR_VALIDATION;
   196→    }
   197→
   198→    /* Compose canonical JSON recipe */
   199→    cJSON *recipe_json = compose_recipe_json(fragments);
   200→    if (!recipe_json)
   201→    {
   202→        HC_LOG_ERROR("artifact_factory: failed to compose JSON recipe");
   203→        return AF_STATUS_ERR_INTERNAL;
   204→    }
   205→
   206→    char *recipe_str = cJSON_PrintUnformatted(recipe_json);
   207→    cJSON_Delete(recipe_json);
   208→    if (!recipe_str)
   209→    {
   210→        HC_LOG_ERROR("artifact_factory: cJSON_PrintUnformatted() failed");
   211→        return AF_STATUS_ERR_OOM;
   212→    }
   213→
   214→    /* Derive deterministic ID */
   215→    char artifact_id[ARTIFACT_ID_HEX_SIZE];
   216→    sha256_hex(recipe_str, strlen(recipe_str), artifact_id);
   217→
   218→    /* Persist recipe to LedgerCore */
   219→    if (!persist_to_ledger(artifact_id, recipe_str))
   220→    {
   221→        HC_LOG_ERROR("artifact_factory: failed to persist artifact to ledger");
   222→        free(recipe_str);
   223→        return AF_STATUS_ERR_DEPENDENCY;
   224→    }
   225→
   226→    /* Construct runtime artifact object (stack-allocated) for event emission */
   227→    artifact_t artifact = {
   228→        .state      = ART_STATE_DRAFT,
   229→        .created_at = time(NULL)
   230→    };
   231→    strncpy(artifact.id, artifact_id, sizeof(artifact.id));
   232→    strncpy(artifact.creator, creator_addr, sizeof(artifact.creator) - 1);
   233→    artifact.recipe.shader   = fragments->shader   ? strdup(fragments->shader)   : NULL;
   234→    artifact.recipe.audio    = fragments->audio    ? strdup(fragments->audio)    : NULL;
   235→    artifact.recipe.metadata = fragments->metadata ? strdup(fragments->metadata) : NULL;
   236→
   237→    /* Emit event into mesh */
   238→    emit_event_artifact_minted(&artifact);
   239→
   240→    /* Populate output */
   241→    if (out_artifact_id)
   242→        strcpy(out_artifact_id, artifact_id);
   243→
   244→    /* Clean up */
   245→    free(artifact.recipe.shader);
   246→    free(artifact.recipe.audio);
   247→    free(artifact.recipe.metadata);
   248→    free(recipe_str);
   249→
   250→    HC_LOG_INFO("artifact_factory: successfully minted artifact %s", artifact_id);
   251→    return AF_STATUS_OK;
