   256→/*---------------------------------------------------------------------------*/
   257→
   258→/**
   259→ * Basic heuristic validation of recipe fragments.
   260→ * In production this would call out to a sandboxed compiler / linter.
   261→ */
   262→static bool validate_fragments(const artifact_fragments_t *fr)
   263→{
   264→    if (!fr->shader || !fr->metadata)
   265→        return false; /* Mandatory fields */
   266→
   267→    /* Size checks (prevent DoS memory bombs) */
   268→    size_t shader_len   = strlen(fr->shader);
   269→    size_t audio_len    = fr->audio ? strlen(fr->audio) : 0;
   270→    size_t metadata_len = strlen(fr->metadata);
   271→
   272→    if (shader_len   > 64 * 1024   /* 64 kB */
   273→        || audio_len > 128 * 1024  /* 128 kB */
   274→        || metadata_len > 16 * 1024) /* 16 kB */
   275→    {
   276→        return false;
   277→    }
   278→
   279→    /* Metadata must be valid JSON */
   280→    cJSON *meta = cJSON_Parse(fr->metadata);
   281→    if (!meta)
   282→        return false;
   283→    cJSON_Delete(meta);
   284→
   285→    /* TODO: syntax check shader & audio; omitted here for brevity */
   286→
   287→    return true;
   288→}
