   290→/**
   291→ * Compose the canonical recipe JSON object from individual fragments.
   292→ * Caller must free returned cJSON with cJSON_Delete().
   293→ */
   294→static cJSON *compose_recipe_json(const artifact_fragments_t *fr)
   295→{
   296→    cJSON *root = cJSON_CreateObject();
   297→    if (!root) return NULL;
   298→
   299→    cJSON_AddItemToObject(root, "shader_fragment",
   300→                          fr->shader ? cJSON_CreateString(fr->shader) : cJSON_CreateNull());
   301→    cJSON_AddItemToObject(root, "audio_fragment",
   302→                          fr->audio ? cJSON_CreateString(fr->audio) : cJSON_CreateNull());
   303→
   304→    /* Metadata fragment is already JSON—parse and embed to maintain types */
   305→    cJSON *meta = cJSON_Parse(fr->metadata);
   306→    if (meta)
   307→    {
   308→        cJSON_AddItemToObject(root, "metadata_fragment", meta);
   309→    }
   310→    else
   311→    {
   312→        /* Fallback as raw string to avoid data loss */
   313→        cJSON_AddItemToObject(root, "metadata_fragment",
   314→                              cJSON_CreateString(fr->metadata ? fr->metadata : ""));
   315→    }
   316→
   317→    return root;
   318→}
   319→
   320→/**
   321→ * Compute SHA-256 digest and return as lowercase hex string.
   322→ */
   323→static void sha256_hex(const char *input, size_t len, char out_hex[ARTIFACT_ID_HEX_SIZE])
   324→{
   325→    unsigned char hash[SHA256_DIGEST_LENGTH];
   326→    SHA256((const unsigned char *)input, len, hash);
   327→
   328→    for (int i = 0; i < SHA256_DIGEST_LENGTH; ++i)
   329→        sprintf(out_hex + (i * 2), "%02x", hash[i]);
   330→
   331→    out_hex[ARTIFACT_ID_HEX_SIZE - 1] = '\0';
   332→}
   333→
   334→/**
   335→ * Persist artifact recipe into LedgerCore.  Wraps ledger_client API.
   336→ */
   337→static bool persist_to_ledger(const char *artifact_id, const char *recipe_json)
   338→{
   339→    ledger_record_t record = {
   340→        .key        = (char *)artifact_id,
   341→        .value      = (char *)recipe_json,
   342→        .topic      = LEDGER_TOPIC_ARTIFACTS
   343→    };
   344→    int rc = ledger_client_put(&record);
   345→    return (rc == 0);
   346→}
   347→
   348→/**
   349→ * Emit an “ArtifactMinted” domain event to the mesh.
   350→ */
   351→static void emit_event_artifact_minted(const artifact_t *artifact)
   352→{
   353→    cJSON *evt = cJSON_CreateObject();
   354→    if (!evt) return;
   355→
   356→    cJSON_AddStringToObject(evt, "event_type", "ArtifactMinted");
   357→    cJSON_AddStringToObject(evt, "artifact_id", artifact->id);
   358→    cJSON_AddStringToObject(evt, "creator", artifact->creator);
   359→    cJSON_AddNumberToObject(evt, "timestamp", (double)artifact->created_at);
   360→
   361→    char *payload = cJSON_PrintUnformatted(evt);
   362→    if (!payload)
   363→    {
   364→        cJSON_Delete(evt);
   365→        return;
   366→    }
   367→
   368→    event_msg_t msg = {
   369→        .topic   = "artifact.events",
   370→        .payload = payload,
   371→        .length  = strlen(payload)
   372→    };
   373→
   374→    if (event_bus_publish(&msg) != 0)
   375→        HC_LOG_WARN("artifact_factory: failed to publish ArtifactMinted event");
   376→
   377→    free(payload);
   378→    cJSON_Delete(evt);
   379→}
