   173→        if (c->head == entry)
   174→            c->head = NULL;
   175→
   176→        /* Remove from hash table */
   177→        HASH_DEL(c->entries, entry);
   178→
   179→        /* Free entry */
   180→        free(entry->key);
   181→        free(entry->value);
   182→        cache_entry_t *old = entry;
   183→        entry = entry->prev;
   184→        free(old);
   185→        c->size--;
