   189→static void lru_cache_promote(lru_cache_t *c, cache_entry_t *entry)
   190→{
   191→    /* Move entry to head of LRU list */
   192→    if (entry == c->head)
   193→        return; /* already MRU */
   194→
   195→    /* Detach */
   196→    if (entry->prev)
   197→        entry->prev->next = entry->next;
   198→    if (entry->next)
   199→        entry->next->prev = entry->prev;
   200→    if (c->tail == entry)
   201→        c->tail = entry->prev;
   202→
   203→    /* Insert at head */
   204→    entry->prev = NULL;
   205→    entry->next = c->head;
   206→    if (c->head)
   207→        c->head->prev = entry;
   208→    c->head = entry;
   209→    if (c->tail == NULL)
   210→        c->tail = entry;
   211→}
