   213→static char *lru_cache_get(lru_cache_t *c,
   214→                           const char *key,
   215→                           size_t *value_len_out)
   216→{
   217→    pthread_mutex_lock(&c->mtx);
   218→    cache_entry_t *entry = NULL;
   219→    HASH_FIND_STR(c->entries, key, entry);
   220→
   221→    if (!entry) {
   222→        pthread_mutex_unlock(&c->mtx);
   223→        return NULL;
   224→    }
   225→
   226→    /* Refresh LRU position and check TTL */
   227→    time_t now = time(NULL);
   228→    if ((now - entry->created_at) > DEFAULT_CACHE_TTL_SEC) {
   229→        /* Stale – treat as miss */
   230→        LOG_INFO("Cache expired for key=%s", key);
   231→        HASH_DEL(c->entries, entry);
   232→
   233→        if (entry->prev)
   234→            entry->prev->next = entry->next;
   235→        if (entry->next)
   236→            entry->next->prev = entry->prev;
   237→        if (c->head == entry)
   238→            c->head = entry->next;
   239→        if (c->tail == entry)
   240→            c->tail = entry->prev;
   241→
   242→        free(entry->key);
   243→        free(entry->value);
   244→        free(entry);
   245→        c->size--;
   246→        pthread_mutex_unlock(&c->mtx);
   247→        return NULL;
   248→    }
   249→
   250→    lru_cache_promote(c, entry);
   251→
   252→    char *dup = strndup(entry->value, entry->value_len);
   253→    if (value_len_out)
   254→        *value_len_out = entry->value_len;
   255→
   256→    pthread_mutex_unlock(&c->mtx);
   257→    return dup;
   258→}
