   260→static void lru_cache_put(lru_cache_t *c,
   261→                          const char *key,
   262→                          const char *value,
   263→                          size_t value_len)
   264→{
   265→    pthread_mutex_lock(&c->mtx);
   266→
   267→    cache_entry_t *entry = NULL;
   268→    HASH_FIND_STR(c->entries, key, entry);
   269→    if (entry) {
   270→        /* Update existing */
   271→        free(entry->value);
   272→        entry->value = strndup(value, value_len);
   273→        entry->value_len = value_len;
   274→        entry->created_at = time(NULL);
   275→        lru_cache_promote(c, entry);
   276→    } else {
   277→        /* New entry */
   278→        entry = calloc(1, sizeof(*entry));
   279→        entry->key   = strdup(key);
   280→        entry->value = strndup(value, value_len);
   281→        entry->value_len = value_len;
   282→        entry->created_at = time(NULL);
   283→
   284→        /* Insert into hash & LRU list */
   285→        HASH_ADD_KEYPTR(hh, c->entries, entry->key, strlen(entry->key), entry);
   286→        entry->prev = NULL;
   287→        entry->next = c->head;
   288→        if (c->head)
   289→            c->head->prev = entry;
   290→        c->head = entry;
   291→        if (c->tail == NULL)
   292→            c->tail = entry;
   293→
   294→        c->size++;
   295→    }
   296→
   297→    lru_cache_evict(c); /* Ensure capacity */
   298→    pthread_mutex_unlock(&c->mtx);
   299→}
