   301→static void lru_cache_deinit(lru_cache_t *c)
   302→{
   303→    pthread_mutex_lock(&c->mtx);
   304→    cache_entry_t *cur, *tmp;
   305→    HASH_ITER(hh, c->entries, cur, tmp) {
   306→        HASH_DEL(c->entries, cur);
   307→        free(cur->key);
   308→        free(cur->value);
   309→        free(cur);
   310→    }
   311→    c->head = c->tail = NULL;
   312→    c->size = c->capacity = 0;
   313→    pthread_mutex_unlock(&c->mtx);
   314→    pthread_mutex_destroy(&c->mtx);
   315→}
