   326→static size_t curl_write_cb(void *contents, size_t size, size_t nmemb,
   327→                            void *userp)
   328→{
   329→    size_t realsize = size * nmemb;
   330→    curl_resp_buf_t *buf = (curl_resp_buf_t *)userp;
   331→
   332→    char *ptr = realloc(buf->mem, buf->size + realsize + 1);
   333→    if (!ptr) {
   334→        LOG_ERR("Not enough memory (realloc returned NULL)");
   335→        return 0; /* abort */
   336→    }
   337→    buf->mem = ptr;
   338→    memcpy(&(buf->mem[buf->size]), contents, realsize);
   339→    buf->size += realsize;
   340→    buf->mem[buf->size] = 0;
   341→    return realsize;
   342→}
