   344→static qry_status_t http_get_json(const char *url,
   345→                                  char **out_payload,
   346→                                  size_t *out_len,
   347→                                  long *out_http_code)
   348→{
   349→    CURL *curl = curl_easy_init();
   350→    if (!curl) {
   351→        LOG_ERR("curl_easy_init failed");
   352→        return QRY_ERR_INTERNAL;
   353→    }
   354→
   355→    curl_resp_buf_t chunk = { .mem = malloc(1), .size = 0 };
   356→    struct curl_slist *hdrs = NULL;
   357→
   358→    curl_easy_setopt(curl, CURLOPT_URL, url);
   359→    curl_easy_setopt(curl, CURLOPT_HTTPGET, 1L);
   360→    curl_easy_setopt(curl, CURLOPT_FOLLOWLOCATION, 1L);
   361→    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, curl_write_cb);
   362→    curl_easy_setopt(curl, CURLOPT_WRITEDATA, (void *)&chunk);
   363→    /* Accept JSON */
   364→    hdrs = curl_slist_append(hdrs, "Accept: application/json");
   365→    curl_easy_setopt(curl, CURLOPT_HTTPHEADER, hdrs);
   366→
   367→    CURLcode res = curl_easy_perform(curl);
   368→    if (res != CURLE_OK) {
   369→        LOG_ERR("curl_easy_perform() failed: %s", curl_easy_strerror(res));
   370→        curl_slist_free_all(hdrs);
   371→        curl_easy_cleanup(curl);
   372→        free(chunk.mem);
   373→        return QRY_ERR_NETWORK;
   374→    }
   375→
   376→    long http_code = 0;
   377→    curl_easy_getinfo(curl, CURLINFO_RESPONSE_CODE, &http_code);
   378→    if (out_http_code)
   379→        *out_http_code = http_code;
   380→
   381→    *out_payload = chunk.mem;
   382→    *out_len     = chunk.size;
   383→
   384→    curl_slist_free_all(hdrs);
   385→    curl_easy_cleanup(curl);
   386→    return QRY_OK;
   387→}
