   477→                            "artifact",
   478→                            token_id);
   479→
   480→    char *payload = NULL;
   481→    size_t len = 0;
   482→    long http_code = 0;
   483→    qry_status_t st = http_get_json(url, &payload, &len, &http_code);
   484→    free(url);
   485→
   486→    if (st != QRY_OK)
   487→        return st;
   488→
   489→    if (http_code == 404) {
   490→        free(payload);
   491→        return QRY_ERR_NOT_FOUND;
