E_CAPACITY        1024          /* # of entries  */\n#define DEFAULT_CACHE_TTL_SEC         (60 * 5)      /* 5 min TTL     */\n\n/* =========================================================================\n *  Logging helpers\n * =========================================================================\n */\n#define LOG_FMT(level, fmt, ...) \\\n        fprintf(stderr, \"[%s] (%s:%d) \" fmt \"\\n\", level, __FILE__, __LINE__, \\\n                ##__VA_ARGS__)\n\n#define LOG_INFO(fmt, ...)    LOG_FMT(\"INFO\",    fmt, ##__VA_ARGS__)\n#define LOG_WARN(fmt, ...)    LOG_FMT(\"WARN\",    fmt, ##__VA_ARGS__)\n#define LOG_ERR(fmt, ...)     LOG_FMT(\"ERROR\",   fmt, ##__VA_ARGS__)\n\n/* =========================================================================\n *  Query Service Public API\n * =========================================================================\n */\ntypedef enum {\n    QRY_OK = 0,\n    QRY_ERR_NETWORK      = -1,\n    QRY_ERR_JSON_PARSE   = -2,\n    QRY_ERR_NOT_FOUND    = -3,\n    QRY_ERR_INTERNAL     = -4,\n} qry_status_t;\n\ntypedef struct {\n    char *json_payload;     /* NULL-terminated JSON string (caller must free) */\n    size_t len;             /* length of json_payload                        */\n    long   http_code;       /* underlying HTTP status code                   */\n} qry_response_t;\n\n/*\n *  Initialize global resources (curl, cache, etc.).\n *  Returns 0 on success or negative error code.\n */\nint gallery_query_init(void);\n\n/*\n *  Shutdown global resources and free memory.\n */\nvoid gallery_query_shutdown(void);\n\n/*\n *  Retrieve lifecycle + metadata for a single artifact.\n *  Caller takes ownership of the response and must free it via free().\n */\nqry_status_t gallery_query_get_artifact(const char *token_id,\n                                        qry_response_t *out);\n\n/*\n *  List every artifact token belonging to a gallery/collection.\n */\nqry_status_t gallery_query_list_artifacts(const char *gallery_id,\n                                          qry_response_t *out);\n\n/* =========================================================================\n *  Internal implementation details\n * =========================================================================\n */\n\ntypedef struct cache_entry_s {\n    char *key;              /* UTF-8 string key (token_id / gallery_id) */\n    char *value;            /* JSON blob                                */\n    size_t value_len;\n    time_t created_at;      /* For TTL eviction                         */\n\n    struct cache_entry_s *prev, *next;  /* intrusive LRU list          */\n    UT_hash_handle hh;                   /* uthash handle               */\n} cache_entry_t;\n\ntypedef struct {\n    size_t capacity;\n    size_t size;\n    cache_entry_t *entries;     /* hash table root               */\n    cache_entry_s *head;        /* Most-recently-used            */\n    cache_entry_s *tail;        /* Least-recently-used           */\n    pthread_mutex_t mtx;        /* protect all members           */\n} lru_cache_t;\n\n/* Global singleton state */\nstatic struct {\n    lru_cache_t   cache;\n    char          ledgercore_ep[256];\n    char          factory_ep[256];\n    char          governance_ep[256];\n} g_srv;\n\n/* -------------------------------------------------------------------------\n *  LRU Cache helpers\n * -------------------------------------------------------------------------\n */\nstatic int lru_cache_init(lru_cache_t *c, size_t capacity)\n{\n    if (!c || capacity == 0)\n        return -1;\n    c->capacity = capacity;\n    c->size     = 0;\n    c->entries  = NULL;\n    c->head     = c->tail = NULL;\n    if (pthread_mutex_init(&c->mtx, NULL) != 0) {\n        LOG_ERR(\"pthread_mutex_init failed: %s\", strerror(errno));\n        return -1;\n    }\n    return 0;\n}\n\nstatic void lru_cache_evict(lru_cache_t *c)\n{\n    /* Remove oldest (tail) entry if above capacity or TTL expired */\n    cache_entry_t *entry = c->tail;\n    time_t now = time(NULL);\n\n    while (entry &&\n          (c->size > c->capacity ||\n           (now - entry->created_at) > DEFAULT_CACHE_TTL_SEC)) {\n\n        /* Detach from linked list */\n        if (entry->prev)\n            entry->prev->next = NULL;\n        c->tail = entry->prev;\n        if (c->head == entry)\n            c->head = NULL;\n\n        /* Remove from hash table */\n        HASH_DEL(c->entries, entry);\n\n        /* Free entry */\n        free(entry->key);\n        free(entry->value);\n        cache_entry_t *old = entry;\n        entry = entry->prev;\n        free(old);\n        c->size--;\n    }\n}\n\nstatic void lru_cache_promote(lru_cache_t *c, cache_entry_t *entry)\n{\n    /* Move entry to head of LRU list */\n    if (entry == c->head)\n        return; /* already MRU */\n\n    /* Detach */\n    if (entry->prev)\n        entry->prev->next = entry->next;\n    if (entry->next)\n        entry->next->prev = entry->prev;\n    if (c->tail == entry)\n        c->tail = entry->prev;\n\n    /* Insert at head */\n    entry->prev = NULL;\n    entry->next = c->head;\n    if (c->head)\n        c->head->prev = entry;\n    c->head = entry;\n    if (c->tail == NULL)\n        c->tail = entry;\n}\n\nstatic char *lru_cache_get(lru_cache_t *c,\n                           const char *key,\n                           size_t *value_len_out)\n{\n    pthread_mutex_lock(&c->mtx);\n    cache_entry_t *entry = NULL;\n    HASH_FIND_STR(c->entries, key, entry);\n\n    if (!entry) {\n        pthread_mutex_unlock(&c->mtx);\n        return NULL;\n    }\n\n    /* Refresh LRU position and check TTL */\n    time_t now = time(NULL);\n    if ((now - entry->created_at) > DEFAULT_CACHE_TTL_SEC) {\n        /* Stale – treat as miss */\n        LOG_INFO(\"Cache expired for key=%s\", key);\n        HASH_DEL(c->entries, entry);\n\n        if (entry->prev)\n            entry->prev->next = entry->next;\n        if (entry->next)\n            entry->next->prev = entry->prev;\n        if (c->head == entry)\n            c->head = entry->next;\n        if (c->tail == entry)\n            c->tail = entry->prev;\n\n        free(entry->key);\n        free(entry->value);\n        free(entry);\n        c->size--;\n        pthread_mutex_unlock(&c->mtx);\n        return NULL;\n    }\n\n    lru_cache_promote(c, entry);\n\n    char *dup = strndup(entry->value, entry->value_len);\n    if (value_len_out)\n        *value_len_out = entry->value_len;\n\n    pthread_mutex_unlock(&c->mtx);\n    return dup;\n}\n\nstatic void lru_cache_put(lru_cache_t *c,\n                          const char *key,\n                          const char *value,\n                          size_t value_len)\n{\n    pthread_mutex_lock(&c->mtx);\n\n    cache_entry_t *entry = NULL;\n    HASH_FIND_STR(c->entries, key, entry);\n    if (entry) {\n        /* Update existing */\n        free(entry->value);\n        entry->value = strndup(value, value_len);\n        entry->value_len = value_len;\n        entry->created_at = time(NULL);\n        lru_cache_promote(c, entry);\n    } else {\n        /* New entry */\n        entry = calloc(1, sizeof(*entry));\n        entry->key   = strdup(key);\n        entry->value = strndup(value, value_len);\n        entry->value_len = value_len;\n        entry->created_at = time(NULL);\n\n        /* Insert into hash & LRU list */\n        HASH_ADD_KEYPTR(hh, c->entries, entry->key, strlen(entry->key), entry);\n        entry->prev = NULL;\n        entry->next = c->head;\n        if (c->head)\n            c->head->prev = entry;\n        c->head = entry;\n        if (c->tail == NULL)\n            c->tail = entry;\n\n        c->size++;\n    }\n\n    lru_cache_evict(c); /* Ensure capacity */\n    pthread_mutex_unlock(&c->mtx);\n}\n\nstatic void lru_cache_deinit(lru_cache_t *c)\n{\n    pthread_mutex_lock(&c->mtx);\n    cache_entry_t *cur, *tmp;\n    HASH_ITER(hh, c->entries, cur, tmp) {\n        HASH_DEL(c->entries, cur);\n        free(cur->key);\n        free(cur->value);\n        free(cur);\n    }\n    c->head = c->tail = NULL;\n    c->size = c->capacity = 0;\n    pthread_mutex_unlock(&c->mtx);\n    pthread_mutex_destroy(&c->mtx);\n}\n\n/* -------------------------------------------------------------------------\n *  CURL helpers\n * -------------------------------------------------------------------------\n */\ntypedef struct {\n    char  *mem;\n    size_t size;\n} curl_resp_buf_t;\n\nstatic size_t curl_write_cb(void *contents, size_t size, size_t nmemb,\n                            void *userp)\n{\n    size_t realsize = size * nmemb;\n    curl_resp_buf_t *buf = (curl_resp_buf_t *)userp;\n\n    char *ptr = realloc(buf->mem, buf->size + realsize + 1);\n    if (!ptr) {\n        LOG_ERR(\"Not enough memory (realloc returned NULL)\");\n        return 0; /* abort */\n    }\n    buf->mem = ptr;\n    memcpy(&(buf->mem[buf->size]), contents, realsize);\n    buf->size += realsize;\n    buf->mem[buf->size] = 0;\n    return realsize;\n}\n\nstatic qry_status_t http_get_json(const char *url,\n                                  char **out_payload,\n                                  size_t *out_len,\n                                  long *out_http_code)\n{\n    CURL *curl = curl_easy_init();\n    if (!curl) {\n        LOG_ERR(\"curl_easy_init failed\");\n        return QRY_ERR_INTERNAL;\n    }\n\n    curl_resp_buf_t chunk = { .mem = malloc(1), .size = 0 };\n    struct curl_slist *hdrs = NULL;\n\n    curl_easy_setopt(curl, CURLOPT_URL, url);\n    curl_easy_setopt(curl, CURLOPT_HTTPGET, 1L);\n    curl_easy_setopt(curl, CURLOPT_FOLLOWLOCATION, 1L);\n    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, curl_write_cb);\n    curl_easy_setopt(curl, CURLOPT_WRITEDATA, (void *)&chunk);\n    /* Accept JSON */\n    hdrs = curl_slist_append(hdrs, \"Accept: application/json\");\n    curl_easy_setopt(curl, CURLOPT_HTTPHEADER, hdrs);\n\n    CURLcode res = curl_easy_perform(curl);\n    if (res != CURLE_OK) {\n        LOG_ERR(\"curl_easy_perform() failed: %s\", curl_easy_strerror(res));\n        curl_slist_free_all(hdrs);\n        curl_easy_cleanup(curl);\n        free(chunk.mem);\n        return QRY_ERR_NETWORK;\n    }\n\n    long http_code = 0;\n    curl_easy_getinfo(curl, CURLINFO_RESPONSE_CODE, &http_code);\n    if (out_http_code)\n        *out_http_code = http_code;\n\n    *out_payload = chunk.mem;\n    *out_len     = chunk.size;\n\n    curl_slist_free_all(hdrs);\n    curl_easy_cleanup(curl);\n    return QRY_OK;\n}\n\n/* -------------------------------------------------------------------------\n *  Private utility helpers\n * -------------------------------------------------------------------------\n */\nstatic void populate_endpoints(void)\n{\n    const char *env;\n\n    env = getenv(ENV_LEDGERCORE_ENDPOINT);\n    snprintf(g_srv.ledgercore_ep, sizeof(g_srv.ledgercore_ep), \"%s\",\n             env ? env : DEFAULT_LEDGERCORE_ENDPOINT);\n\n    env = getenv(ENV_FACTORY_ENDPOINT);\n    snprintf(g_srv.factory_ep, sizeof(g_srv.factory_ep), \"%s\",\n             env ? env : DEFAULT_FACTORY_ENDPOINT);\n\n    env = getenv(ENV_GOVERNANCE_ENDPOINT);\n    snprintf(g_srv.governance_ep, sizeof(g_srv.governance_ep), \"%s\",\n             env ? env : DEFAULT_GOVERNANCE_ENDPOINT);\n\n    LOG_INFO(\"LedgerCore endpoint: %s\",      g_srv.ledgercore_ep);\n    LOG_INFO(\"Mint-Factory endpoint: %s\",    g_srv.factory_ep);\n    LOG_INFO(\"Governance-Hall endpoint: %s\", g_srv.governance_ep);\n}\n\n/* =========================================================================\n *  Public API Implementation\n * =========================================================================\n */\nint gallery_query_init(void)\n{\n    memset(&g_srv, 0, sizeof(g_srv));\n\n    if (curl_global_init(CURL_GLOBAL_ALL) != 0) {\n        LOG_ERR(\"curl_global_init failed\");\n        return -1;\n    }\n\n    if (lru_cache_init(&g_srv.cache, DEFAULT_CACHE_CAPACITY) != 0) {\n        curl_global_cleanup();\n        return -1;\n    }\n\n    populate_endpoints();\n    return 0;\n}\n\nvoid gallery_query_shutdown(void)\n{\n    lru_cache_deinit(&g_srv.cache);\n    curl_global_cleanup();\n}\n\n/* --\n *  compose_url():\n *      Build a URL string using the supplied pattern:\n *          base + \"/\" + segment + \"/\" + id\n *\n *      Returns a malloc()'d string that the caller must free.\n * -- */\nstatic char *compose_url(const char *base,\n                         const char *segment,\n                         const char *id)\n{\n    size_t len = strlen(base) + strlen(segment) + strlen(id) + 3;\n    char *url = malloc(len);\n    snprintf(url, len, \"%s/%s/%s\", base, segment, id);\n    return url;\n}\n\nqry_status_t gallery_query_get_artifact(const char *token_id,\n                                        qry_response_t *out)\n{\n    if (!token_id || !out)\n        return QRY_ERR_INTERNAL;\n\n    /* Step 1 – Check in-process cache */\n    size_t cached_len = 0;\n    char *cached = lru_cache_get(&g_srv.cache, token_id, &cached_len);\n    if (cached) {\n        out->json_payload = cached;\n        out->len          = cached_len;\n        out->http_code    = 200;\n        return QRY_OK;\n    }\n\n    /* Step 2 – Query LedgerCore for on-chain state */\n    char *url = compose_url(g_srv.ledgercore_ep,\n                            \"artifact\",\n                            token_id);\n\n    char *payload = NULL;\n    size_t len = 0;\n    long http_code = 0;\n    qry_status_t st = http_get_json(url, &payload, &len, &http_code);\n    free(url);\n\n    if (st != QRY_OK)\n        return st;\n\n    if (http_code == 404) {\n        free(payload);\n        return QRY_ERR_NOT_FOUND;\n    }\n\n    /* Step 3 – Validate JSON (lightweight sanity check) */\n    cJSON *root = cJSON_ParseWithLength(payload, (int)len);\n    if (!root) {\n        LOG_ERR(\"Malformed JSON received for token_id=%s\", token_id);\n        free(payload);\n        return QRY_ERR_JSON_PARSE;\n    }\n    cJSON_Delete(root);\n\n    /* Step 4 – Insert into cache on success */\n    lru_cache_put(&g_srv.cache, token_id, payload, len);\n\n    out->json_payload = payload;\n    out->len          = len;\n    out->http_code    = http_code;\n    return QRY_OK;\n}\n\nqry_status_t gallery_query_list_artifacts(const char *gallery_id,\n                                          qry_response_t *out)\n{\n    if (!gallery_id || !out)\n        return QRY_ERR_INTERNAL;\n\n    size_t cached_len = 0;\n    char *cached = lru_cache_get(&g_srv.cache, gallery_id, &cached_len);\n    if (cached) {\n        out->json_payload = cached;\n        out->len          = cached_len;\n        out->http_code    = 200;\n        return QRY_OK;\n    }\n\n    /* Compose URL – gallery listing lives behind the Factory service */\n    char *url = compose_url(g_srv.factory_ep,\n                            \"gallery\",\n                            gallery_id);\n\n    char *payload = NULL;\n    size_t len = 0;\n    long http_code = 0;\n    qry_status_t st = http_get_json(url, &payload, &len, &http_code);\n    free(url);\n\n    if (st != QRY_OK)\n        return st;\n\n    if (http_code == 404) {\n        free(payload);\n        return QRY_ERR_NOT_FOUND;\n    }\n\n    cJSON *root = cJSON_ParseWithLength(payload, (int)len);\n    if (!root) {\n        LOG_ERR(\"Malformed JSON received for gallery_id=%s\", gallery_id);\n        free(payload);\n        return QRY_ERR_JSON_PARSE;\n    }\n    cJSON_Delete(root);\n\n    lru_cache_put(&g_srv.cache, gallery_id, payload, len);\n\n    out->json_payload = payload;\n    out->len          = len;\n    out->http_code    = http_code;\n    return QRY_OK;\n}\n\n/* =========================================================================\n *  Self-Test (Compile-time gated)\n * =========================================================================\n *  To run: gcc -DTEST_QUERY_SERVICE query_service.c -lcurl -lpthread -lcjson\n * ------------------------------------------------------------------------- */\n#ifdef TEST_QUERY_SERVICE\nint main(int argc, char **argv)\n{\n    if (gallery_query_init() != 0)\n        return EXIT_FAILURE;\n\n    qry_response_t resp = {0};\n    if (gallery_query_get_artifact(\"demo-token-1\", &resp) == QRY_OK) {\n        printf(\"Artifact JSON: %.*s\\n\", (int)resp.len, resp.json_payload);\n        free(resp.json_payload);\n    } else {\n        LOG_ERR(\"Failed to fetch demo-token-1\");\n    }\n\n    if (gallery_query_list_artifacts(\"demo-gallery\", &resp) == QRY_OK) {\n        printf(\"Gallery JSON: %.*s\\n\", (int)resp.len, resp.json_payload);\n        free(resp.json_payload);\n    } else {\n        LOG_ERR(\"Failed to fetch demo-gallery\");\n    }\n\n    gallery_query_shutdown();\n    return EXIT_SUCCESS;\n}\n#endif /* TEST_QUERY_SERVICE */\n", "numLines": 592, "startLine": 1, "totalLines": 592}}

1→/*
     2→ *  HoloCanvas -- Kafka Client Abstraction Layer
     3→ *
     4→ *  File:    HoloCanvas/shared/kafka_client/hc_kafka.c
     5→ *  Project: HoloCanvas – A Micro-Gallery Blockchain for Generative Artifacts
     6→ *
     7→ *  Description:
     8→ *      Thin(ish) wrapper around librdkafka that provides the HoloCanvas
     9→ *      micro-services with a sane, opinionated interface for publishing and
    10→ *      consuming protobuf / JSON events on the project-wide Event Bus.
    11→ *
    12→ *  Design notes:
    13→ *      • One producer instance and one consumer instance are multiplexed out of
    14→ *        a single rd_kafka_t handle to conserve file descriptors.
    15→ *      • Thread-safety is provided by an internal mutex guarding the producer’s
    16→ *        shared queue; the consumer runs in the caller’s thread.
    17→ *      • Delivery reports are routed to a ring-buffer so that infrequent callers
    18→ *        can inspect them without registering a full callback.
    19→ *      • All public API symbols are prefixed with “hc_kafka_”.
    20→ *
    21→ *  Build:
    22→ *      gcc -Wall -Wextra -pedantic -std=c11 \
    23→ *          -I/path/to/librdkafka/include -L/path/to/librdkafka/lib \
    24→ *          -lrdkafka -pthread -o hc_kafka.o -c hc_kafka.c
    25→ */
    26→
    27→#include <stdio.h>
    28→#include <stdlib.h>
    29→#include <string.h>
    30→#include <stdarg.h>
    31→#include <signal.h>
    32→#include <pthread.h>
    33→#include <errno.h>
    34→#include <time.h>
    35→
    36→#include <librdkafka/rdkafka.h>
    37→
    38→#include "hc_kafka.h"   /* Public header exported to the rest of the project    */
    39→
    40→/* ────────────────────────────────────────────────────────────────────────── */
    41→/*                           Compile-time Defaults                           */
    42→
    43→#ifndef HC_KAFKA_LOG_PREFIX
    44→#   define HC_KAFKA_LOG_PREFIX  "[hc_kafka] "
    45→#endif
    46→
    47→#ifndef HC_KAFKA_MAX_DELIVERY_RING
    48→#   define HC_KAFKA_MAX_DELIVERY_RING  1024  /* Power-of-two strongly advised */
    49→#endif
    50→
    51→/* ────────────────────────────────────────────────────────────────────────── */
    52→/*                                 Logging                                   */
    53→
    54→static void hc_kafka_vlog(enum hc_kafka_log_level lvl,
    55→                          const char *fmt, va_list ap)
    56→{
    57→    const char *pfx = HC_KAFKA_LOG_PREFIX;
    58→    FILE *stream   = (lvl >= HC_KAFKA_LOG_ERROR) ? stderr : stdout;
    59→
    60→    flockfile(stream);
    61→    fprintf(stream, "%s", pfx);
    62→    vfprintf(stream, fmt, ap);
    63→    fprintf(stream, "\n");
    64→    funlockfile(stream);
    65→}
    66→
    67→static void hc_kafka_log(enum hc_kafka_log_level lvl, const char *fmt, ...)
    68→{
    69→    va_list ap;
    70→    va_start(ap, fmt);
    71→    hc_kafka_vlog(lvl, fmt, ap);
    72→    va_end(ap);
    73→}
    74→
    75→/* -------------------------------------------------------------------------- */
    76→/*                        Ring-buffer for delivery reports                    */
    77→
    78→typedef struct {
    79→    hc_kafka_delivery_t buf[HC_KAFKA_MAX_DELIVERY_RING];
    80→    size_t              head;
    81→    size_t              tail;
    82→    pthread_mutex_t     mutex;
    83→} delivery_ring_t;
    84→
    85→static void ring_init(delivery_ring_t *r)
    86→{
    87→    memset(r, 0, sizeof(*r));
    88→    pthread_mutex_init(&r->mutex, NULL);
    89→}
    90→
    91→static void ring_push(delivery_ring_t *r, const hc_kafka_delivery_t *item)
    92→{
    93→    pthread_mutex_lock(&r->mutex);
    94→    r->buf[r->head] = *item;
    95→    r->head = (r->head + 1) % HC_KAFKA_MAX_DELIVERY_RING;
    96→    if (r->head == r->tail) {          /* overwrite oldest */
    97→        r->tail = (r->tail + 1) % HC_KAFKA_MAX_DELIVERY_RING;
    98→    }
    99→    pthread_mutex_unlock(&r->mutex);
   100→}
   101→
   102→static int ring_pop(delivery_ring_t *r, hc_kafka_delivery_t *out)
   103→{
   104→    int found = 0;
   105→    pthread_mutex_lock(&r->mutex);
   106→    if (r->tail != r->head) {
   107→        *out = r->buf[r->tail];
   108→        r->tail = (r->tail + 1) % HC_KAFKA_MAX_DELIVERY_RING;
   109→        found = 1;
   110→    }
   111→    pthread_mutex_unlock(&r->mutex);
   112→    return found;
   113→}
