   115→/* ────────────────────────────────────────────────────────────────────────── */
   116→/*                    Internal structure representing a client               */
   117→
   118→struct hc_kafka_client {
   119→    rd_kafka_t       *rk;             /* Unified handle (producer & consumer) */
   120→    rd_kafka_conf_t  *conf;           /* Base configuration object           */
   121→    rd_kafka_topic_partition_list_t *subscribed;
   122→    pthread_mutex_t   producer_mutex; /* Guards produce() and queue length   */
   123→    delivery_ring_t   d_ring;         /* Ring-buffer for delivery reports    */
   124→    char             *brokers;
   125→    char             *client_id;
   126→    volatile int      run;
   127→};
   128→
   129→/* -------------------------------------------------------------------------- */
   130→/*                        librdkafka Callback Shims                           */
   131→
   132→static void rebalance_cb(rd_kafka_t *rk,
   133→                         rd_kafka_resp_err_t err,
   134→                         rd_kafka_topic_partition_list_t *partitions,
   135→                         void *opaque)
   136→{
   137→    hc_kafka_client_t *cli = (hc_kafka_client_t *)opaque;
   138→    switch (err) {
   139→        case RD_KAFKA_RESP_ERR__ASSIGN_PARTITIONS:
   140→            hc_kafka_log(HC_KAFKA_LOG_INFO,
   141→                         "Assigned %d partition(s) to consumer",
   142→                         partitions->cnt);
   143→            rd_kafka_assign(rk, partitions);
   144→            break;
   145→        case RD_KAFKA_RESP_ERR__REVOKE_PARTITIONS:
   146→            hc_kafka_log(HC_KAFKA_LOG_INFO,
   147→                         "Partitions revoked");
   148→            rd_kafka_assign(rk, NULL);
   149→            break;
   150→        default:
   151→            rd_kafka_assign(rk, NULL);
   152→            break;
   153→    }
   154→    (void)cli;
   155→}
   156→
   157→static void logger_cb(const rd_kafka_t *rk, int level,
   158→                      const char *fac, const char *buf)
   159→{
   160→    (void)rk; (void)fac;
   161→    enum hc_kafka_log_level lvl;
   162→
   163→    /* Map librdkafka logs to our own */
   164→    if (level >= 6)
   165→        lvl = HC_KAFKA_LOG_DEBUG;
   166→    else if (level >= 4)
   167→        lvl = HC_KAFKA_LOG_INFO;
   168→    else
   169→        lvl = HC_KAFKA_LOG_WARN;
   170→
   171→    hc_kafka_log(lvl, "rdkafka: %s", buf);
   172→}
   173→
   174→static void dr_msg_cb(rd_kafka_t *rk,
   175→                      const rd_kafka_message_t *m,
   176→                      void *opaque)
   177→{
   178→    hc_kafka_client_t *cli = (hc_kafka_client_t *)opaque;
   179→    hc_kafka_delivery_t d  = {
   180→        .topic      = m->rkt ? rd_kafka_topic_name(m->rkt) : NULL,
   181→        .partition  = m->partition,
   182→        .offset     = m->offset,
   183→        .err        = m->err,
   184→        .opaque     = m->_private
   185→    };
   186→
   187→    ring_push(&cli->d_ring, &d);
   188→
   189→    if (m->err) {
   190→        hc_kafka_log(HC_KAFKA_LOG_ERROR,
   191→                     "Delivery failed: %s",
   192→                     rd_kafka_err2str(m->err));
   193→    } else {
   194→        hc_kafka_log(HC_KAFKA_LOG_DEBUG,
   195→                     "Delivered message to %s [%d] @ %" PRId64,
   196→                     d.topic, d.partition, d.offset);
   197→    }
   198→    (void)rk;
   199→}
   200→
   201→/* ────────────────────────────────────────────────────────────────────────── */
   202→/*                              Public  API                                  */
   203→
   204→hc_kafka_client_t *hc_kafka_client_new(const hc_kafka_conf_t *user_conf)
   205→{
   206→    hc_kafka_client_t *cli = calloc(1, sizeof(*cli));
   207→    if (!cli) {
   208→        hc_kafka_log(HC_KAFKA_LOG_ERROR, "OOM creating hc_kafka_client");
   209→        return NULL;
   210→    }
   211→
   212→    cli->conf = rd_kafka_conf_new();
   213→
   214→    rd_kafka_conf_set_log_cb(cli->conf, logger_cb);
   215→    rd_kafka_conf_set_dr_msg_cb(cli->conf, dr_msg_cb);
   216→    rd_kafka_conf_set_rebalance_cb(cli->conf, rebalance_cb);
   217→    rd_kafka_conf_set_opaque(cli->conf, cli);
   218→
   219→    /* Apply caller-provided overrides */
   220→    if (user_conf->bootstrap_servers)
   221→        rd_kafka_conf_set(cli->conf, "bootstrap.servers",
   222→                          user_conf->bootstrap_servers, NULL, 0);
   223→
   224→    if (user_conf->client_id)
