   377→int hc_kafka_client_publish(hc_kafka_client_t *cli,
   378→                            const char *topic,
   379→                            const char *key,
   380→                            const void *payload,
   381→                            size_t len,
   382→                            int partition,
   383→                            void *opaque)
   384→{
   385→    if (!cli || !topic || !payload)
   386→        return -EINVAL;
   387→
   388→    pthread_mutex_lock(&cli->producer_mutex);
   389→
   390→    rd_kafka_resp_err_t err = rd_kafka_producev(
   391→        cli->rk,
   392→        RD_KAFKA_V_TOPIC(topic),
   393→        RD_KAFKA_V_PARTITION(partition),
   394→        RD_KAFKA_V_KEY((void *)key, key ? strlen(key) : 0),
   395→        RD_KAFKA_V_VALUE((void *)payload, len),
   396→        RD_KAFKA_V_OPAQUE(opaque),
   397→        RD_KAFKA_V_END);
   398→
   399→    if (err) {
   400→        hc_kafka_log(HC_KAFKA_LOG_ERROR,
   401→                     "Produce failed: %s", rd_kafka_err2str(err));
   402→        pthread_mutex_unlock(&cli->producer_mutex);
   403→        return -1;
   404→    }
   405→
   406→    /* Pump the internal producer queue */
   407→    rd_kafka_poll(cli->rk, 0);
   408→    pthread_mutex_unlock(&cli->producer_mutex);
   409→    return 0;
   410→}
