   412→size_t hc_kafka_client_drain_reports(hc_kafka_client_t *cli,
   413→                                     hc_kafka_delivery_t *out,
   414→                                     size_t max_count)
   415→{
   416→    if (!cli || !out || max_count == 0)
   417→        return 0;
   418→
   419→    size_t cnt = 0;
   420→    while (cnt < max_count && ring_pop(&cli->d_ring, &out[cnt]))
   421→        ++cnt;
   422→    return cnt;
   423→}
