    25→/* -------------------------------------------------------------------------- */
    26→/*                            Public-facing API                               */
    27→/* -------------------------------------------------------------------------- */
    28→
    29→/* Error codes returned by the state-machine public functions. */
    30→typedef enum {
    31→    SM_OK = 0,
    32→    SM_ERR_INVALID_ARG      = -1,
    33→    SM_ERR_INVALID_STATE    = -2,
    34→    SM_ERR_INVALID_TRANS    = -3,
    35→    SM_ERR_LOCK_FAILED      = -4,
    36→    SM_ERR_OUT_OF_MEMORY    = -5,
    37→    SM_ERR_INTERNAL         = -6
    38→} sm_error_t;
    39→
    40→/* The canonical Artifact life-cycle states. */
    41→typedef enum {
    42→    ART_STATE_DRAFT = 0,
    43→    ART_STATE_CURATED,
    44→    ART_STATE_AUCTION,
    45→    ART_STATE_FRACTIONALIZED,
    46→    ART_STATE_STAKED,
    47→    ART_STATE_RETIRED,
    48→
    49→    ART_STATE_MAX
    50→} art_state_t;
    51→
    52→/* Forward declaration so that clients can maintain opaque handles. */
    53→typedef struct artifact_sm artifact_sm_t;
    54→
    55→/* Create / Destroy */
    56→sm_error_t sm_create(uint64_t artifact_id,
    57→                     art_state_t initial_state,
    58→                     artifact_sm_t **out_handle);
    59→void       sm_destroy(artifact_sm_t *handle);
    60→
    61→/* Query & Mutation */
    62→sm_error_t sm_get_state(artifact_sm_t *handle, art_state_t *out_state);
    63→sm_error_t sm_transition(artifact_sm_t *handle,
    64→                         art_state_t    target_state,
    65→                         const char    *actor /* e.g. wallet addr */);
    66→
    67→/* Introspection helpers */
    68→const char *sm_state_to_str(art_state_t state);
