    70→/* -------------------------------------------------------------------------- */
    71→/*                          Private implementation                            */
    72→/* -------------------------------------------------------------------------- */
    73→
    74→/* Utility: timespec (nanoseconds since boot) */
    75→static inline uint64_t
    76→epoch_millis(void)
    77→{
    78→    struct timespec ts;
    79→    clock_gettime(CLOCK_REALTIME, &ts);
    80→    return (uint64_t)ts.tv_sec * 1000ULL + (ts.tv_nsec / 1000000ULL);
    81→}
    82→
    83→/* Transition table: allowed[next][current] = true if current -> next */
    84→static const bool g_allowed_transitions[ART_STATE_MAX][ART_STATE_MAX] = {
    85→    /*                 FROM ➜   DRAFT CURATED AUCTION FRACT  STAKED RETIRED */
    86→    /* TO = DRAFT */        {  true,  false,  false,  false, false, false },
    87→    /* CURATED */           {  true,  true,   false,  false, false, false },
    88→    /* AUCTION */           { false,  true,   true,   false, false, false },
    89→    /* FRACTIONALIZED */    { false, false,   true,   true,  true,  false },
    90→    /* STAKED */            { false, false,  false,   true,  true,  false },
    91→    /* RETIRED */           {  true,  true,   true,   true,  true,  true  }
    92→};
