   128→
   129→const char *
   130→sm_state_to_str(art_state_t state)
   131→{
   132→    static const char *kNames[ART_STATE_MAX] = {
   133→        [ART_STATE_DRAFT]         = "DRAFT",
   134→        [ART_STATE_CURATED]       = "CURATED",
   135→        [ART_STATE_AUCTION]       = "AUCTION",
   136→        [ART_STATE_FRACTIONALIZED]= "FRACTIONALIZED",
   137→        [ART_STATE_STAKED]        = "STAKED",
   138→        [ART_STATE_RETIRED]       = "RETIRED"
   139→    };
   140→    if (state >= ART_STATE_MAX) { return "UNKNOWN"; }
   141→    return kNames[state];
   142→}
