   144→sm_error_t
   145→sm_create(uint64_t artifact_id,
   146→          art_state_t initial_state,
   147→          artifact_sm_t **out_handle)
   148→{
   149→    if (!out_handle) { return SM_ERR_INVALID_ARG; }
   150→    if (initial_state >= ART_STATE_MAX) { return SM_ERR_INVALID_STATE; }
   151→
   152→    artifact_sm_t *sm = calloc(1, sizeof(*sm));
   153→    if (!sm) { return SM_ERR_OUT_OF_MEMORY; }
   154→
   155→    sm->id              = artifact_id;
   156→    sm->state           = initial_state;
   157→    sm->last_updated_ms = epoch_millis();
   158→
   159→    if (pthread_mutex_init(&sm->mtx, NULL) != 0) {
   160→        free(sm);
   161→        return SM_ERR_INTERNAL;
   162→    }
   163→
   164→    *out_handle = sm;
   165→    log_event(LOG_INFO,
   166→              "[SM] Created state-machine for Artifact %" PRIu64 " (%s)",
   167→              artifact_id, sm_state_to_str(initial_state));
   168→    return SM_OK;
   169→}
   170→
   171→void
   172→sm_destroy(artifact_sm_t *handle)
   173→{
   174→    if (!handle) { return; }
   175→    pthread_mutex_destroy(&handle->mtx);
   176→    memset(handle, 0, sizeof(*handle));
   177→    free(handle);
   178→}
   179→
   180→sm_error_t
   181→sm_get_state(artifact_sm_t *handle, art_state_t *out_state)
   182→{
   183→    if (!handle || !out_state) { return SM_ERR_INVALID_ARG; }
   184→    if (pthread_mutex_lock(&handle->mtx) != 0) { return SM_ERR_LOCK_FAILED; }
   185→    *out_state = handle->state;
   186→    pthread_mutex_unlock(&handle->mtx);
   187→    return SM_OK;
   188→}
   189→
   190→sm_error_t
   191→sm_transition(artifact_sm_t *handle,
   192→              art_state_t    target_state,
   193→              const char    *actor)
   194→{
   195→    if (!handle) { return SM_ERR_INVALID_ARG; }
   196→    if (target_state >= ART_STATE_MAX) { return SM_ERR_INVALID_STATE; }
   197→
   198→    if (pthread_mutex_lock(&handle->mtx) != 0) { return SM_ERR_LOCK_FAILED; }
   199→
   200→    art_state_t current = handle->state;
   201→
   202→    /* Validate transition */
   203→    if (!g_allowed_transitions[target_state][current]) {
   204→        pthread_mutex_unlock(&handle->mtx);
   205→        log_event(LOG_WARNING,
   206→                  "[SM] Invalid transition: %s -> %s (Artifact %" PRIu64 ")",
   207→                  sm_state_to_str(current),
   208→                  sm_state_to_str(target_state),
   209→                  handle->id);
   210→        return SM_ERR_INVALID_TRANS;
   211→    }
   212→
   213→    /* Apply transition */
   214→    handle->state           = target_state;
   215→    handle->last_updated_ms = epoch_millis();
   216→
   217→    pthread_mutex_unlock(&handle->mtx);
   218→
   219→    /* Notify observers / event bus */
   220→    publish_state_change(handle->id, current, target_state, actor);
   221→
   222→    return SM_OK;
   223→}
