    88→/* Hex-encoding helpers ----------------------------------------------------- */
    89→static void
    90→bytes_to_hex(const uint8_t *bytes, size_t len, char *hex_out)
    91→{
    92→    static const char lut[] = "0123456789abcdef";
    93→    for (size_t i = 0; i < len; ++i) {
    94→        hex_out[i * 2]     = lut[(bytes[i] >> 4) & 0x0F];
    95→        hex_out[i * 2 + 1] = lut[ bytes[i]       & 0x0F];
    96→    }
    97→    hex_out[len * 2] = '\0';
    98→}
