   100→static int
   101→hex_to_bytes(const char *hex, uint8_t *bytes_out, size_t max_len)
   102→{
   103→    size_t hex_len = strlen(hex);
   104→    if (hex_len % 2 != 0 || hex_len / 2 > max_len)
   105→        return -1;
   106→
   107→    for (size_t i = 0; i < hex_len / 2; ++i) {
   108→        unsigned int byte;
   109→        if (sscanf(&hex[i * 2], "%2x", &byte) != 1)
   110→            return -1;
   111→        bytes_out[i] = (uint8_t)byte;
   112→    }
   113→    return (int)(hex_len / 2);
   114→}
