   123→/* Reads the body of an evhttp_request into a null-terminated buffer.
   124→ * The returned pointer must be freed by the caller. */
   125→static char *
   126→read_request_body(struct evhttp_request *req)
   127→{
   128→    struct evbuffer *buf = evhttp_request_get_input_buffer(req);
   129→    size_t len           = evbuffer_get_length(buf);
   130→    if (len == 0 || len > MAX_JSON_BODY) {
   131→        return NULL;
   132→    }
   133→
   134→    char *data = calloc(1, len + 1);
   135→    if (!data)
   136→        return NULL;
   137→
   138→    evbuffer_copyout(buf, data, len);
   139→    return data;
   140→}
