   142→/* -------------------------------------------------------------------------- */
   143→/*                                Key-Store                                  */
   144→/* -------------------------------------------------------------------------- */
   145→
   146→/*
   147→ * The keystore is a simple in-memory, thread-safe map:
   148→ *      address (hex-encoded pubkey)  ->  wallet_entry_t
   149→ *
   150→ * WARNING: This is for demonstration only.  Never store private keys
   151→ *          like this in production.
   152→ */
   153→
   154→typedef struct wallet_entry {
   155→    uint8_t  pubkey[crypto_sign_PUBLICKEYBYTES];
   156→    uint8_t  seckey[crypto_sign_SECRETKEYBYTES];
   157→    char     address[crypto_sign_PUBLICKEYBYTES * 2 + 1]; /* hex-encoded */
   158→    UT_hash_handle hh; /* makes this structure hashable */
   159→} wallet_entry_t;
   160→
   161→static wallet_entry_t *g_keystore = NULL;
   162→static pthread_mutex_t g_keystore_lock = PTHREAD_MUTEX_INITIALIZER;
   163→
   164→static wallet_entry_t *
   165→keystore_lookup(const char *address)
   166→{
   167→    wallet_entry_t *entry = NULL;
   168→    pthread_mutex_lock(&g_keystore_lock);
   169→    HASH_FIND_STR(g_keystore, address, entry);
   170→    pthread_mutex_unlock(&g_keystore_lock);
   171→    return entry;
   172→}
   173→
   174→static int
   175→keystore_insert(const uint8_t pubkey[crypto_sign_PUBLICKEYBYTES],
   176→                const uint8_t seckey[crypto_sign_SECRETKEYBYTES],
   177→                char **address_out)
   178→{
   179→    wallet_entry_t *entry = malloc(sizeof *entry);
   180→    if (!entry)
   181→        return -1;
   182→
   183→    memcpy(entry->pubkey, pubkey, crypto_sign_PUBLICKEYBYTES);
   184→    memcpy(entry->seckey, seckey, crypto_sign_SECRETKEYBYTES);
   185→
   186→    bytes_to_hex(pubkey, crypto_sign_PUBLICKEYBYTES, entry->address);
   187→
   188→    pthread_mutex_lock(&g_keystore_lock);
   189→    HASH_ADD_STR(g_keystore, address, entry);
   190→    pthread_mutex_unlock(&g_keystore_lock);
   191→
   192→    if (address_out)
   193→        *address_out = strdup(entry->address);
   194→
   195→    return 0;
   196→}
