   226→/* Helper: send JSON response and free the cJSON object. */
   227→static void
   228→send_json_reply(struct evhttp_request *req, int code, cJSON *json)
   229→{
   230→    char *rendered = cJSON_PrintUnformatted(json);
   231→    cJSON_Delete(json);
   232→
   233→    struct evbuffer *buf = evbuffer_new();
   234→    evbuffer_add_printf(buf, "%s", rendered);
   235→    free(rendered);
   236→
   237→    evhttp_add_header(evhttp_request_get_output_headers(req),
   238→                      "Content-Type", JSON_CONTENT_TYPE);
   239→    evhttp_send_reply(req, code, "OK", buf);
   240→
   241→    evbuffer_free(buf);
   242→}
