   256→/* Handler: POST /v1/wallet/create --------------------------------------- */
   257→static void
   258→handle_wallet_create(struct evhttp_request *req, void *arg)
   259→{
   260→    (void)arg;
   261→    if (req->type != EVHTTP_REQ_POST) {
   262→        evhttp_send_reply(req, HTTP_BADMETHOD, "Method Not Allowed", NULL);
   263→        return;
   264→    }
   265→
   266→    uint8_t pubkey[crypto_sign_PUBLICKEYBYTES];
   267→    uint8_t seckey[crypto_sign_SECRETKEYBYTES];
   268→
   269→    if (crypto_sign_keypair(pubkey, seckey) != 0) {
   270→        LOG_ERR("crypto_sign_keypair() failed");
   271→        evhttp_send_reply(req, HTTP_INTERNAL, "Crypto Error", NULL);
   272→        return;
   273→    }
   274→
   275→    char *address = NULL;
   276→    if (keystore_insert(pubkey, seckey, &address) != 0) {
   277→        evhttp_send_reply(req, HTTP_INTERNAL, "Keystore Error", NULL);
   278→        return;
   279→    }
   280→
   281→    char pub_hex[crypto_sign_PUBLICKEYBYTES * 2 + 1];
   282→    bytes_to_hex(pubkey, crypto_sign_PUBLICKEYBYTES, pub_hex);
   283→
   284→    cJSON *json = cJSON_CreateObject();
   285→    cJSON_AddStringToObject(json, "address", address);
   286→    cJSON_AddStringToObject(json, "public_key", pub_hex);
   287→
   288→    send_json_reply(req, HTTP_OK, json);
   289→    free(address);
   290→}
