   292→/* Handler: GET /v1/wallet/<addr>/balance ------------------------------- */
   293→static void
   294→handle_wallet_balance(struct evhttp_request *req, void *arg)
   295→{
   296→    (void)arg;
   297→    if (req->type != EVHTTP_REQ_GET) {
   298→        evhttp_send_reply(req, HTTP_BADMETHOD, "Method Not Allowed", NULL);
   299→        return;
   300→    }
   301→
   302→    const char *uri  = evhttp_request_get_uri(req);
   303→    struct evhttp_uri *decoded = evhttp_uri_parse(uri);
   304→    if (!decoded) {
   305→        evhttp_send_reply(req, HTTP_BADREQUEST, "Bad URI", NULL);
   306→        return;
   307→    }
   308→
   309→    const char *path = evhttp_uri_get_path(decoded);
   310→    /* Path format: /v1/wallet/<address>/balance */
   311→    char address[crypto_sign_PUBLICKEYBYTES * 2 + 1] = {0};
   312→    if (sscanf(path, "/v1/wallet/%64[a-f0-9]/balance", address) != 1) {
   313→        evhttp_send_reply(req, HTTP_BADREQUEST, "Bad Address", NULL);
   314→        evhttp_uri_free(decoded);
   315→        return;
   316→    }
   317→    evhttp_uri_free(decoded);
   318→
   319→    uint64_t balance = 0;
   320→    if (ledger_get_balance(address, &balance) != 0) {
   321→        evhttp_send_reply(req, HTTP_INTERNAL, "Ledger Error", NULL);
   322→        return;
   323→    }
   324→
   325→    cJSON *json = cJSON_CreateObject();
   326→    cJSON_AddStringToObject(json, "address", address);
   327→    cJSON_AddNumberToObject(json, "balance", (double)balance);
   328→    send_json_reply(req, HTTP_OK, json);
   329→}
