   331→/* Handler: POST /v1/wallet/sign ----------------------------------------- */
   332→static void
   333→handle_wallet_sign(struct evhttp_request *req, void *arg)
   334→{
   335→    (void)arg;
   336→    if (req->type != EVHTTP_REQ_POST) {
   337→        evhttp_send_reply(req, HTTP_BADMETHOD, "Method Not Allowed", NULL);
   338→        return;
   339→    }
   340→
   341→    char *body = read_request_body(req);
   342→    if (!body) {
   343→        evhttp_send_reply(req, HTTP_BADREQUEST, "Empty Body", NULL);
   344→        return;
   345→    }
   346→
   347→    cJSON *json = cJSON_Parse(body);
   348→    free(body);
   349→    if (!json) {
   350→        evhttp_send_reply(req, HTTP_BADREQUEST, "Invalid JSON", NULL);
   351→        return;
   352→    }
   353→
   354→    cJSON *j_addr = cJSON_GetObjectItemCaseSensitive(json, "address");
   355→    cJSON *j_payload = cJSON_GetObjectItemCaseSensitive(json, "payload");
   356→
   357→    if (!cJSON_IsString(j_addr) || !cJSON_IsString(j_payload)) {
   358→        cJSON_Delete(json);
   359→        evhttp_send_reply(req, HTTP_BADREQUEST, "Missing Fields", NULL);
   360→        return;
   361→    }
   362→
   363→    const char *address = j_addr->valuestring;
   364→    const char *payload_hex = j_payload->valuestring;
   365→
   366→    wallet_entry_t *entry = keystore_lookup(address);
   367→    if (!entry) {
   368→        cJSON_Delete(json);
   369→        evhttp_send_reply(req, HTTP_NOTFOUND, "Wallet Not Found", NULL);
   370→        return;
   371→    }
   372→
   373→    uint8_t payload_bin[1024];
   374→    int payload_len = hex_to_bytes(payload_hex, payload_bin, sizeof payload_bin);
   375→    if (payload_len < 0) {
   376→        cJSON_Delete(json);
   377→        evhttp_send_reply(req, HTTP_BADREQUEST, "Bad Payload Hex", NULL);
   378→        return;
   379→    }
   380→
