     3→//
     4→//  File:    holocanvas.proto
     5→//  Project: HoloCanvas – A Micro-Gallery Blockchain for Generative Artifacts
     6→//
     7→//  Summary:
     8→//      Core cross-service protocol definitions.  All micro-services—Cryptograph,
     9→//      LedgerCore, MintFactory, GalleryGateway, DeFiGarden, OracleBridge,
    10→//      WalletProxy, and GovernanceHall—share this file to guarantee binary
    11→//      compatibility across language stacks (C, Go, Rust, TS, …).
    12→//
    13→//      The protocol is designed for high-throughput event streaming while still
    14→//      allowing fine-grained, request/response RPCs where appropriate.
    15→//      Multiplexed topic identifiers (topic_id) let a single bidirectional
    16→//      stream carry heterogeneous event types without sacrificing strong type
    17→//      safety.
    18→//
    19→//  Notes:
    20→//      1. All domain objects include an immutable uuid and a RFC-3339 timestamp.
    21→//      2. Blockchain “block_height” indexes finalized state on the roll-up
    22→//         layer.  A value of 0 means “pending / mem-pool”.                 ]:-)
    23→//
    24→//  Copyright © 2023-2024 The HoloCanvas Authors.
    25→//
    26→
    27→package holocanvas.v1;
    28→
    29→option csharp_namespace  = "HoloCanvas.Proto";
    30→option java_package      = "com.holocanvas.proto.v1";
    31→option go_package        = "github.com/holocanvas/proto/gen/go/holocanvas/v1;holocanvasv1";
    32→option objc_class_prefix = "HCX";
    33→
    34→// ---------------------------------------------------------------------------
    35→// Google Well-Known Types
    36→// ---------------------------------------------------------------------------
    37→import "google/protobuf/any.proto";
    38→import "google/protobuf/struct.proto";
    39→import "google/protobuf/timestamp.proto";
    40→
    41→// ---------------------------------------------------------------------------
    42→// ENUMERATIONS
    43→// ---------------------------------------------------------------------------
    44→
    45→enum ArtifactState {
    46→    ARTIFACT_STATE_UNSPECIFIED  = 0;
    47→    ARTIFACT_STATE_DRAFT        = 1;
    48→    ARTIFACT_STATE_CURATED      = 2;
    49→    ARTIFACT_STATE_AUCTION      = 3;
    50→    ARTIFACT_STATE_FRACTIONAL   = 4;
    51→    ARTIFACT_STATE_STAKED       = 5;
    52→    ARTIFACT_STATE_ARCHIVED     = 6;
    53→}
    54→
    55→enum MediaKind {
    56→    MEDIA_KIND_UNSPECIFIED = 0;
    57→    MEDIA_KIND_SHADER      = 1;   // GLSL / WGSL fragment
    58→    MEDIA_KIND_AUDIO       = 2;   // WebAudio / MIDI
    59→    MEDIA_KIND_METADATA    = 3;   // JSON-LD, IPFS CID, etc.
    60→}
    61→
    62→enum GovernanceAction {
    63→    GOVERNANCE_ACTION_UNSPECIFIED = 0;
    64→    GOVERNANCE_ACTION_MINT_RIGHTS = 1;
    65→    GOVERNANCE_ACTION_CURATE      = 2;
    66→    GOVERNANCE_ACTION_EVOLVE      = 3;
    67→    GOVERNANCE_ACTION_FREEZE      = 4;
    68→    GOVERNANCE_ACTION_BURN        = 5;
    69→}
    70→
    71→// ---------------------------------------------------------------------------
    72→// CORE DOMAIN OBJECTS
    73→// ---------------------------------------------------------------------------
    74→
    75→// A cryptographically provable identity (wallet, service, or DAO).
    76→message Principal {
    77→    string  did           = 1;  // W3C Decentralized Identifier, e.g. "did:key:…"
    78→    bytes   public_key    = 2;  // Raw secp256k1 key bytes
    79→    string  alias         = 3;  // Human-friendly label
    80→}
    81→
    82→// Represents a single layer of media inside an Artifact.
    83→message MediaLayer {
    84→    string      uuid            = 1;  // Layer UUID
    85→    MediaKind   kind            = 2;
    86→    string      content_uri     = 3;  // IPFS / Arweave / HTTPS URI
    87→    bytes       content_hash    = 4;  // SHA-256 digest of raw bytes
    88→    uint32      ordinal         = 5;  // Z-index for compositing
    89→    google.protobuf.Timestamp created_at = 6;
    90→}
    91→
    92→// Immutable recipe captured at mint-time.
    93→message ArtifactRecipe {
    94→    string                        uuid          = 1;
    95→    repeated MediaLayer           layers        = 2;
    96→    google.protobuf.Struct        metadata      = 3;  // Arbitrary creator-supplied JSON
    97→    string                        factory_addr  = 4;  // On-chain smart-contract address
    98→    google.protobuf.Timestamp     created_at    = 5;
    99→}
   100→
   101→// NFT Artifact tracked on-chain.
   102→message Artifact {
   103→    string               uuid           = 1;
   104→    ArtifactState        state          = 2;
   105→    ArtifactRecipe       recipe         = 3;
   106→    Principal            owner          = 4;
   107→    uint64               block_height   = 5;  // 0 => pending
   108→    google.protobuf.Timestamp updated_at = 6;
   109→}
   110→
   111→// Generic financial amount in Wei, USD-cents, etc.
   112→message Amount {
   113→    string  currency = 1; // e.g. "wei", "usdc"
   114→    uint64  value    = 2;
   115→}
   116→
   117→// Bid placed during Auction state.
   118→message Bid {
   119→    string                   uuid         = 1;
   120→    string                   artifact_uuid= 2;
   121→    Principal                bidder       = 3;
   122→    Amount                   amount       = 4;
   123→    google.protobuf.Timestamp placed_at   = 5;
   124→}
   125→
   126→// Staking position.
   127→message Stake {
   128→    string                   uuid          = 1;
   129→    string                   artifact_uuid = 2;
   130→    Principal                staker        = 3;
   131→    Amount                   amount        = 4;
   132→    uint32                   lock_days     = 5;
   133→    google.protobuf.Timestamp staked_at    = 6;
   134→}
   135→
   136→// Governance proposal document.
   137→message GovernanceProposal {
   138→    string                       uuid            = 1;
   139→    string                       artifact_uuid   = 2;
   140→    GovernanceAction             action          = 3;
   141→    google.protobuf.Struct       params          = 4;  // action-specific
   142→    Principal                    proposer        = 5;
   143→    google.protobuf.Timestamp    submitted_at    = 6;
   144→    repeated GovernanceVote      votes           = 7;
   145→}
   146→
   147→// Individual vote.
   148→message GovernanceVote {
   149→    Principal                    voter        = 1;
   150→    bool                         approve      = 2;
   151→    google.protobuf.Timestamp    cast_at      = 3;
   152→}
   153→
   154→// Data injected by external oracle feeds.
   155→message OracleEvent {
   156→    string                       uuid          = 1;
   157→    string                       source        = 2; // e.g. "openweather"
   158→    google.protobuf.Struct       payload       = 3;
   159→    google.protobuf.Timestamp    observed_at   = 4;
   160→}
   161→
   162→// ---------------------------------------------------------------------------
   163→// TRANSACTION ENVELOPE
   164→// ---------------------------------------------------------------------------
   165→
   166→// Unified event wrapper for streaming across Kafka / gRPC.
   167→message CanvasEvent {
   168→    string   uuid        = 1;
   169→    oneof    body {
   170→        Artifact            artifact              = 10;
   171→        Bid                 bid                   = 11;
   172→        Stake               stake                 = 12;
   173→        GovernanceProposal  proposal              = 13;
   174→        OracleEvent         oracle                = 14;
   175→    }
   176→    // Topic to aid in routing through pub/sub fabric.
   177→    string   topic_id    = 20; // e.g. "artifact.{uuid}" or "governance.global"
   178→    uint64   block_height= 21;
   179→    google.protobuf.Timestamp emitted_at = 22;
   180→}
   181→
   182→// ---------------------------------------------------------------------------
   183→// SERVICE APIs
   184→// ---------------------------------------------------------------------------
   185→
   186→// 1. Factory Pattern – composable mint pipeline.
   187→service MintFactory {
   188→    // Mint a brand-new Artifact from a recipe.
   189→    rpc Mint(ArtifactRecipe) returns (Artifact);
   190→
   191→    // Retrieve an existing Artifact (regardless of state).
   192→    rpc GetArtifact(GetArtifactRequest) returns (Artifact);
   193→
   194→    // Subscribe to live state transitions for a specific Artifact.
   195→    rpc WatchArtifact(WatchArtifactRequest) returns (stream CanvasEvent);
   196→}
   197→
   198→message GetArtifactRequest {
   199→    string artifact_uuid = 1;
   200→}
   201→
   202→message WatchArtifactRequest {
   203→    string artifact_uuid = 1;
   204→}
   205→
   206→// 2. LedgerCore – canonical blockchain interface (light wrapper around rollup node).
   207→service LedgerCore {
   208→    // Append a signed transaction to the roll-up mem-pool.
   209→    rpc SubmitEvent(CanvasEvent) returns (SubmitEventResponse);
   210→
   211→    // Stream finalized blocks for indexing or archival.
   212→    rpc StreamBlocks(StreamBlocksRequest) returns (stream CanvasEvent);
   213→}
   214→
   215→message SubmitEventResponse {
   216→    string  tx_hash      = 1;
   217→    uint64  mempool_seq  = 2;
   218→}
   219→
   220→message StreamBlocksRequest {
   221→    uint64 from_block = 1;
   222→}
   223→
   224→// 3. DeFiGarden – staking & fractionalization hub.
   225→service DeFiGarden {
   226→    rpc StakeArtifact(Stake) returns (Stake);
   227→    rpc Unstake(UnstakeRequest) returns (Stake);
   228→    rpc WatchStakes(WatchStakesRequest) returns (stream Stake);
   229→}
   230→
   231→message UnstakeRequest {
   232→    string stake_uuid = 1;
   233→}
   234→
   235→message WatchStakesRequest {
   236→    string artifact_uuid = 1;
   237→}
   238→
   239→// 4. GovernanceHall – DAO governance portal.
   240→service GovernanceHall {
   241→    rpc Propose(GovernanceProposal) returns (GovernanceProposal);
   242→    rpc Vote(GovernanceVote) returns (GovernanceProposal);
   243→    rpc WatchGovernance(WatchGovernanceRequest) returns (stream GovernanceProposal);
   244→}
   245→
   246→message WatchGovernanceRequest {
   247→    string artifact_uuid = 1; // empty = global stream
   248→}
   249→
   250→// 5. OracleBridge – gateway for external data feeds.
   251→service OracleBridge {
   252→    rpc InjectOracleData(OracleEvent) returns (OracleEvent);
   253→    rpc WatchOracle(WatchOracleRequest) returns (stream OracleEvent);
   254→}
   255→
   256→message WatchOracleRequest {
   257→    string source = 1; // empty = all
   258→}
   259→
   260→// 6. WalletProxy – abstraction layer for user wallets.
   261→service WalletProxy {
   262→    rpc SignAndSubmit(SignedPayload) returns (SubmitEventResponse);
   263→    rpc GetBalance(GetBalanceRequest) returns (Amount);
   264→}
   265→
   266→message SignedPayload {
   267→    bytes  payload   = 1;
   268→    bytes  signature = 2;
   269→}
   270→
   271→message GetBalanceRequest {
   272→    Principal account = 1;
   273→}
   274→
   275→// 7. GalleryGateway – read-only aggregation for UI/REST.
   276→service GalleryGateway {
   277→    rpc ListArtifacts(ListArtifactsRequest) returns (stream Artifact);
   278→}
   279→
   280→message ListArtifactsRequest {
   281→    ArtifactState state_filter = 1; // UNSPECIFIED = all
   282→}
   283→
   284→// ---------------------------------------------------------------------------
   285→// BACKWARD-COMPATIBILITY NOTES
   286→// ---------------------------------------------------------------------------
   287→// • Whenever you need to remove a field, use the “reserved” keyword to prevent
   288→//   accidental reuse.  (See Proto3 versioning guide.)
   289→// • Keep numeric tags stable once published.
   290→// ---------------------------------------------------------------------------

