   110→/* ----  librdkafka callbacks ---------------------------------------------- */
   111→
   112→static void rebalance_cb(rd_kafka_t *rk,
   113→                         rd_kafka_resp_err_t err,
   114→                         rd_kafka_topic_partition_list_t *partitions,
   115→                         void *opaque) {
