   150→/* ----  Public API --------------------------------------------------------- */
   151→
   152→EventListener *event_listener_create(const EventListenerConfig *cfg,
   153→                                     MuseActionStrategy       *strategy) {
   154→    rd_kafka_conf_t *kconf = rd_kafka_conf_new();
   155→    if (!kconf) {
   156→        LOG_ERROR("Unable to allocate rd_kafka_conf");
   157→        return NULL;
   158→    }
   159→
   160→    /* copy config into librdkafka */
   161→    rd_kafka_conf_set_log_cb(kconf, log_cb);
   162→    rd_kafka_conf_set_error_cb(kconf, error_cb);
   163→    rd_kafka_conf_set_rebalance_cb(kconf, rebalance_cb);
   164→    rd_kafka_conf_set_opaque(kconf, NULL); /* will set later */
   165→
   166→    if (rd_kafka_conf_set(kconf, "bootstrap.servers",
   167→                          cfg->brokers, NULL, 0) != RD_KAFKA_CONF_OK) {
   168→        LOG_ERROR("Invalid 'bootstrap.servers' value: %s", cfg->brokers);
