   212→int event_listener_start(EventListener *listener) {
   213→    if (listener->running) {
   214→        LOG_WARN("EventListener already running");
   215→        return 0;
   216→    }
   217→
   218→    if (!listener->strategy || !listener->strategy->on_event) {
   219→        LOG_ERROR("No valid strategy attached to EventListener");
   220→        return -1;
   221→    }
   222→
   223→    rd_kafka_resp_err_t err =
   224→        rd_kafka_subscribe(listener->rk, listener->topics);
   225→    if (err != RD_KAFKA_RESP_ERR_NO_ERROR) {
   226→        LOG_ERROR("Failed to subscribe to topic: %s",
   227→                  rd_kafka_err2str(err));
   228→        return -1;
   229→    }
   230→
   231→    listener->running = true;
   232→    int rc = pthread_create(&listener->thr, NULL, listener_thread, listener);
   233→    if (rc != 0) {
   234→        LOG_ERROR("Failed to spawn listener thread: %s", strerror(rc));
   235→        listener->running = false;
   236→        return -1;
   237→    }
   238→
   239→    LOG_INFO("EventListener started for topic '%s'", listener->topics->elems[0].topic);
   240→    return 0;
   241→}
   242→
   243→void event_listener_stop(EventListener *listener) {
   244→    if (!listener || !listener->running)
   245→        return;
   246→
   247→    listener->running = false;
   248→    pthread_join(listener->thr, NULL);
   249→
   250→    LOG_INFO("EventListener stopped");
   251→}
   252→
   253→void event_listener_destroy(EventListener *listener) {
   254→    if (!listener)
   255→        return;
   256→
   257→    if (listener->running)
   258→        event_listener_stop(listener);
   259→
   260→    rd_kafka_unsubscribe(listener->rk);
   261→    rd_kafka_destroy(listener->rk);
   262→    rd_kafka_topic_partition_list_destroy(listener->topics);
   263→
   264→    free(listener);
   265→}
