   267→/* ----  Thread routine ---------------------------------------------------- */
   268→
   269→static void *listener_thread(void *arg) {
   270→    EventListener *listener = arg;
   271→    signal(SIGINT, sig_handler);
   272→    signal(SIGTERM, sig_handler);
   273→
   274→    while (listener->running && !g_shutdown) {
   275→        rd_kafka_message_t *rkmsg =
   276→            rd_kafka_consumer_poll(listener->rk, 100 /* ms */);
   277→
   278→        if (!rkmsg)
   279→            continue; /* timeout – poll again */
   280→
   281→        if (rkmsg->err) {
   282→            if (rkmsg->err == RD_KAFKA_RESP_ERR__PARTITION_EOF) {
   283→                LOG_DEBUG("Reached end of partition %"PRId32
   284→                          " at offset %"PRId64,
   285→                          rkmsg->partition, rkmsg->offset);
   286→            } else {
   287→                LOG_WARN("Consume error: %s",
   288→                         rd_kafka_message_errstr(rkmsg));
   289→            }
   290→            rd_kafka_message_destroy(rkmsg);
   291→            continue;
   292→        }
   293→
   294→        /* Dispatch user payload */
   295→        if (dispatch_event(listener,
   296→                           (const char *)rkmsg->payload,
   297→                           rkmsg->len) != 0) {
   298→            LOG_WARN("Failed to dispatch event (offset %"PRId64")",
   299→                     rkmsg->offset);
   300→        }
   301→
   302→        rd_kafka_message_destroy(rkmsg);
   303→    }
   304→
   305→    rd_kafka_consumer_close(listener->rk);
   306→    return NULL;
   307→}
