   309→/* ----  Event dispatch ---------------------------------------------------- */
   310→
   311→static int dispatch_event(EventListener *listener,
   312→                          const char *payload, size_t len) {
   313→    json_error_t jerr;
   314→    json_t *root = json_loadb(payload, len, 0, &jerr);
   315→    if (!root) {
   316→        LOG_WARN("JSON parse failed: %s (line %d)", jerr.text, jerr.line);
   317→        return -1;
   318→    }
   319→
   320→    json_t *type = json_object_get(root, "type");
   321→    if (!json_is_string(type)) {
   322→        LOG_WARN("Event missing string 'type' field");
   323→        json_decref(root);
   324→        return -1;
   325→    }
   326→
   327→    const char *etype = json_string_value(type);
   328→    LOG_INFO("Received event: %s", etype);
   329→
   330→    /* Build a thin wrapper for plug-in */
   331→    MuseEvent evt = {
   332→        .raw_json = root,
   333→        .type     = etype,
   334→    };
   335→
   336→    int rc = listener->strategy->on_event(listener->strategy, &evt);
   337→    if (rc != 0)
   338→        LOG_WARN("Strategy returned non-zero (%d) for event %s", rc, etype);
   339→
   340→    json_decref(root);
   341→    return rc;
   342→}
