   315→/* ------------------------------------------------------------------------- *
   316→ *                    Consensus / Validator Selection                        *
   317→ * ------------------------------------------------------------------------- */
   318→
   319→/*
   320→ * pos_strategy_select_proposer()
   321→ * ------------------------------
   322→ * Called by the block-production pipeline to pick the next validator who
   323→ * is eligible to create a block.  Uses a VRF to achieve randomness that
   324→ * can be independently verified by all peers.
   325→ *
   326→ * Returns 0 on success and fills `out_addr`.
   327→ */
   328→int
   329→pos_strategy_select_proposer(const uint8_t prev_block_hash[crypto_hash_sha256_BYTES],
   330→                             wallet_addr_t out_addr)
   331→{
   332→    pthread_rwlock_rdlock(&g_ctx.rwlock);
   333→    if (g_ctx.total_stake == 0 || g_ctx.v_len == 0) {
   334→        pthread_rwlock_unlock(&g_ctx.rwlock);
   335→        HC_LOG_ERROR("[PoS] no stake available for selection");
   336→        return -1;
   337→    }
   338→
   339→    int rc = vrf_elect(&g_ctx, prev_block_hash, out_addr);
   340→    pthread_rwlock_unlock(&g_ctx.rwlock);
   341→
   342→    return rc;
   343→}
