   345→
   346→/* ------------------------------------------------------------------------- *
   347→ *                        Internal helper functions                          *
   348→ * ------------------------------------------------------------------------- */
   349→
   350→/*
   351→ * ensure_capacity()
   352→ * -----------------
   353→ * Grow the validator array if necessary.
   354→ */
   355→static int
   356→ensure_capacity(pos_ctx_t *ctx)
   357→{
   358→    if (ctx->v_len < ctx->v_cap)
   359→        return 0;
   360→
   361→    size_t new_cap = ctx->v_cap * 2;
   362→    validator_entry_t *tmp = realloc(ctx->validators,
   363→                                     new_cap * sizeof(validator_entry_t));
   364→    if (!tmp) {
   365→        perror("[PoS] realloc validators");
   366→        return -1;
   367→    }
   368→    ctx->validators = tmp;
   369→    ctx->v_cap = new_cap;
   370→    return 0;
   371→}
   372→
   373→
   374→/*
   375→ * find_validator()
   376→ * ----------------
   377→ * Return the index of a validator in the array, or ‑1 if not present.
   378→ * Linear search is acceptable for few hundred validators; for larger sets an
   379→ * ordered map should be used (omitted for brevity).
   380→ */
   381→static ssize_t
