   422→ * The VRF simulates a beacon: H = Hash(prev_hash || validator_pub || epoch).
   423→ * Each validator computes H and compares it with a threshold derived from
   424→ * stake/total.  The smallest valid H wins.  For centralised selection (this
   425→ * service) we compute H for all candidates.
   426→ */
   427→static int
   428→vrf_elect(const pos_ctx_t *ctx,
   429→          const uint8_t prev_block_hash[crypto_hash_sha256_BYTES],
   430→          wallet_addr_t out_selected)
   431→{
   432→    uint8_t min_hash[crypto_hash_sha256_BYTES];
