   453→            memcpy(min_hash, h, sizeof(min_hash));
   454→            memcpy(out_selected, v->address, WALLET_ADDR_LEN);
   455→            selected = true;
   456→        }
   457→    }
   458→
   459→    if (!selected)
   460→        return -1;
   461→
   462→    return 0;
   463→}
   464→
   465→
   466→/*
   467→ * apply_block_rewards()
   468→ * ---------------------
   469→ * Credit proposer with block reward plus fees, and distribute a portion to
   470→ * delegators (omitted for brevity).
   471→ */
   472→static int
   473→apply_block_rewards(pos_ctx_t *ctx,
   474→                    const wallet_addr_t proposer,
   475→                    uint64_t block_fees)
   476→{
   477→    static const uint64_t BASE_REWARD = 5 * HC_COINS; /* 5 tokens per block */
