[metadata] {"type": "text", "file": {"filePath": "/app/project/services/ledger_core/src/strategies/pos_strategy.c", "content": "/*\n * HoloCanvas – LedgerCore\n * Proof-of-Stake Consensus Strategy\n *\n * File:    strategies/pos_strategy.c\n * Author:  HoloCanvas Core Team\n *\n * Description:\n *   This file implements the Proof-of-Stake (PoS) consensus plug-in for the\n *   LedgerCore micro-service.  The strategy is loaded at runtime through a\n *   Strategy-Pattern interface (see pos_strategy.h) and receives a stream of\n *   ledger events via the internal Event-Bus.  The PoS module is responsible\n *   for:\n *\n *     • Managing validator stake tables\n *     • Electing the next block proposer with a stake-weighted VRF\n *     • Verifying block signatures and stake lock-ups\n *     • Distributing block rewards and slashing misbehaving validators\n *\n *   The implementation is production-grade and is optimised for readability\n *   and robustness rather than raw performance.  Critical sections are\n *   protected by pthread mutexes; cryptographic operations rely on libsodium.\n *\n *   NOTE: The surrounding infrastructure (ledger storage, event bus, etc.)\n *         is mocked by forward declarations to keep this file self-contained.\n *         In the full code-base these come from their respective headers.\n *\n * License:\n *   Apache-2.0\n */\n\n#include <assert.h>\n#include <errno.h>\n#include <inttypes.h>\n#include <sodium.h>\n#include <stdbool.h>\n#include <stdint.h>\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n#include <pthread.h>\n#include \"pos_strategy.h\"  /* Public interface */\n#include \"../include/crypto_utils.h\"      /* crypto_sign_block(), hash(), … */\n#include \"../include/event_bus.h\"         /* event_bus_publish(), … */\n#include \"../include/ledger_storage.h\"    /* ledger_get_balance(), … */\n#include \"../include/logger.h\"            /* HC_LOG_DEBUG(), … */\n\n/* ------------------------------------------------------------------------- *\n *                              Local  Types                                 *\n * ------------------------------------------------------------------------- */\n\n/* Validator entry kept in memory; periodically snapshotted to disk */\ntypedef struct validator_entry_s\n{\n    wallet_addr_t  address;        /* 32-byte public key (bech32-decoded) */\n    uint64_t       stake;          /* Currently bonded stake              */\n    uint64_t       locked_until;   /* Epoch height until which stake is locked */\n    uint64_t       rewards;        /* Pending rewards (lazy withdrawn)    */\n    bool           jailed;         /* true when validator is slashed      */\n} validator_entry_t;\n\n/* Main PoS context – one per service instance */\ntypedef struct pos_ctx_s\n{\n    validator_entry_t *validators; /* Dynamic array                       */\n    size_t             v_len;      /* Elements in the array               */\n    size_t             v_cap;      /* Capacity                            */\n\n    uint64_t           total_stake;/* Aggregate bonded stake              */\n    uint64_t           current_epoch;\n    event_bus_t       *bus;        /* Weak ref to global Event-Bus        */\n\n    pthread_rwlock_t   rwlock;     /* Protects validators & total_stake   */\n} pos_ctx_t;\n\n/* ------------------------------------------------------------------------- *\n *                       Forward Declarations / Helpers                      *\n * ------------------------------------------------------------------------- */\n\nstatic int      ensure_capacity(pos_ctx_t *ctx);\nstatic ssize_t  find_validator(pos_ctx_t *ctx, const wallet_addr_t addr);\nstatic int      add_validator(pos_ctx_t *ctx,\n                              const wallet_addr_t addr,\n                              uint64_t stake);\n\nstatic int      vrf_elect(const pos_ctx_t *ctx,\n                          const uint8_t previous_block_hash[crypto_hash_sha256_BYTES],\n                          wallet_addr_t out_selected);\n\nstatic int      apply_block_rewards(pos_ctx_t *ctx,\n                                    const wallet_addr_t proposer,\n                                    uint64_t block_fees);\n\nstatic int      slash_validator(pos_ctx_t *ctx,\n                                const wallet_addr_t address,\n                                const char *reason);\n\n/* ------------------------------------------------------------------------- *\n *                       Public  Interface  (Strategy)                       *\n * ------------------------------------------------------------------------- */\n\nstatic pos_ctx_t g_ctx;  /* Singleton instance – strategy is process-local */\n\n\n/*\n * pos_strategy_init()\n * -------------------\n * Initialise libsodium (if necessary), internal state and subscribe to the\n * Event-Bus streams required by the PoS module.\n */\nint\npos_strategy_init(event_bus_t *bus)\n{\n    if (sodium_init() == -1) {\n        fprintf(stderr, \"[PoS] libsodium init failed\\n\");\n        return -1;\n    }\n\n    memset(&g_ctx, 0, sizeof(g_ctx));\n    g_ctx.bus = bus;\n    pthread_rwlock_init(&g_ctx.rwlock, NULL);\n\n    /* Pre-allocate validator table with a sane default */\n    g_ctx.v_cap = 64;\n    g_ctx.validators = calloc(g_ctx.v_cap, sizeof(validator_entry_t));\n    if (!g_ctx.validators) {\n        perror(\"[PoS] calloc validators\");\n        return -1;\n    }\n\n    /* Subscribe to ledger events (mocked) */\n    event_bus_subscribe(bus, EVENT_STAKE_BOND,  pos_strategy_on_event);\n    event_bus_subscribe(bus, EVENT_STAKE_UNBOND,pos_strategy_on_event);\n    event_bus_subscribe(bus, EVENT_NEW_BLOCK,   pos_strategy_on_event);\n\n    HC_LOG_INFO(\"[PoS] strategy initialised\");\n    return 0;\n}\n\n\n/*\n * pos_strategy_shutdown()\n * -----------------------\n * Flush any in-memory state to durable storage and cleanup allocations.\n */\nvoid\npos_strategy_shutdown(void)\n{\n    pthread_rwlock_wrlock(&g_ctx.rwlock);\n\n    /* In a real implementation we would persist validator snapshots here */\n\n    free(g_ctx.validators);\n    g_ctx.validators = NULL;\n    g_ctx.v_len      = 0;\n    g_ctx.v_cap      = 0;\n    g_ctx.total_stake= 0;\n\n    pthread_rwlock_unlock(&g_ctx.rwlock);\n    pthread_rwlock_destroy(&g_ctx.rwlock);\n\n    HC_LOG_INFO(\"[PoS] strategy shut down\");\n}\n\n\n/*\n * pos_strategy_on_event()\n * -----------------------\n * Central entry point for Event-Bus callbacks.  Handles three primary event\n * classes: stake bond/unbond, and new block arrival.\n */\nvoid\npos_strategy_on_event(const event_t *ev)\n{\n    switch (ev->type) {\n\n    case EVENT_STAKE_BOND:\n        pos_strategy_handle_bond((const stake_event_t *)ev->payload);\n        break;\n\n    case EVENT_STAKE_UNBOND:\n        pos_strategy_handle_unbond((const stake_event_t *)ev->payload);\n        break;\n\n    case EVENT_NEW_BLOCK:\n        pos_strategy_handle_block((const block_event_t *)ev->payload);\n        break;\n\n    default:\n        HC_LOG_WARN(\"[PoS] unknown event type: %d\", (int)ev->type);\n    }\n}\n\n\n/* ------------------------------------------------------------------------- *\n *                          Event  Handlers                                  *\n * ------------------------------------------------------------------------- */\n\n/*\n * Handle stake bonding.  Updates validator table and total stake.\n */\nvoid\npos_strategy_handle_bond(const stake_event_t *ev)\n{\n    int rc;\n    pthread_rwlock_wrlock(&g_ctx.rwlock);\n\n    ssize_t idx = find_validator(&g_ctx, ev->staker);\n    if (idx < 0) {\n        /* New validator */\n        rc = add_validator(&g_ctx, ev->staker, ev->amount);\n        if (rc != 0) {\n            HC_LOG_ERROR(\"[PoS] failed to add validator\");\n            pthread_rwlock_unlock(&g_ctx.rwlock);\n            return;\n        }\n    } else {\n        validator_entry_t *v = &g_ctx.validators[idx];\n        v->stake += ev->amount;\n        v->locked_until = g_ctx.current_epoch + POS_MIN_LOCK_EPOCHS;\n    }\n\n    g_ctx.total_stake += ev->amount;\n    pthread_rwlock_unlock(&g_ctx.rwlock);\n\n    HC_LOG_DEBUG(\"[PoS] bonded %\" PRIu64 \" to validator %.8s…, total=%\" PRIu64,\n                 ev->amount, ev->staker, g_ctx.total_stake);\n}\n\n\n/*\n * Handle stake unbonding request.  Stake is not immediately released: we place\n * it in a cooldown queue (omitted for brevity) and unlock once the holding\n * period expires.\n */\nvoid\npos_strategy_handle_unbond(const stake_event_t *ev)\n{\n    pthread_rwlock_wrlock(&g_ctx.rwlock);\n\n    ssize_t idx = find_validator(&g_ctx, ev->staker);\n    if (idx < 0) {\n        HC_LOG_WARN(\"[PoS] unbond from unknown validator %.8s…\", ev->staker);\n        pthread_rwlock_unlock(&g_ctx.rwlock);\n        return;\n    }\n\n    validator_entry_t *v = &g_ctx.validators[idx];\n    if (v->stake < ev->amount) {\n        HC_LOG_ERROR(\"[PoS] unbond exceeds stake\");\n        pthread_rwlock_unlock(&g_ctx.rwlock);\n        return;\n    }\n\n    v->stake -= ev->amount;\n    g_ctx.total_stake -= ev->amount;\n\n    /* TODO: Push to cooldown queue for delayed release */\n\n    pthread_rwlock_unlock(&g_ctx.rwlock);\n\n    HC_LOG_DEBUG(\"[PoS] unbonded %\" PRIu64 \" from validator %.8s…, remaining=%\"\n                 PRIu64, ev->amount, ev->staker, v->stake);\n}\n\n\n/*\n * Handle new block arrival.  Verify proposer signature and stake, distribute\n * fees and reward, then increment epoch if necessary.\n */\nvoid\npos_strategy_handle_block(const block_event_t *ev)\n{\n    const block_t *blk = &ev->block;\n\n    /* 1. Verify signature */\n    if (crypto_verify_block(blk) != 0) {\n        HC_LOG_ERROR(\"[PoS] invalid block signature\");\n        /* TODO: Reject block on the ledger pipeline */\n        return;\n    }\n\n    /* 2. Ensure proposer is valid and not jailed */\n    pthread_rwlock_rdlock(&g_ctx.rwlock);\n    ssize_t idx = find_validator(&g_ctx, blk->proposer);\n    if (idx < 0) {\n        pthread_rwlock_unlock(&g_ctx.rwlock);\n        HC_LOG_ERROR(\"[PoS] proposer %.8s… not in validator set\", blk->proposer);\n        return;\n    }\n\n    const validator_entry_t *v = &g_ctx.validators[idx];\n    if (v->jailed) {\n        pthread_rwlock_unlock(&g_ctx.rwlock);\n        HC_LOG_ERROR(\"[PoS] jailed proposer %.8s…\", blk->proposer);\n        /* Slash attempt */\n        slash_validator(&g_ctx, blk->proposer, \"Proposed block while jailed\");\n        return;\n    }\n    pthread_rwlock_unlock(&g_ctx.rwlock);\n\n    /* 3. Apply rewards */\n    if (apply_block_rewards(&g_ctx, blk->proposer, blk->fees) != 0) {\n        HC_LOG_ERROR(\"[PoS] reward distribution failed\");\n    }\n\n    /* 4. Advance epoch if block boundary crossed */\n    if (blk->height % POS_BLOCKS_PER_EPOCH == 0) {\n        g_ctx.current_epoch++;\n        HC_LOG_INFO(\"[PoS] epoch advanced to %\" PRIu64, g_ctx.current_epoch);\n    }\n}\n\n\n/* ------------------------------------------------------------------------- *\n *                    Consensus / Validator Selection                        *\n * ------------------------------------------------------------------------- */\n\n/*\n * pos_strategy_select_proposer()\n * ------------------------------\n * Called by the block-production pipeline to pick the next validator who\n * is eligible to create a block.  Uses a VRF to achieve randomness that\n * can be independently verified by all peers.\n *\n * Returns 0 on success and fills `out_addr`.\n */\nint\npos_strategy_select_proposer(const uint8_t prev_block_hash[crypto_hash_sha256_BYTES],\n                             wallet_addr_t out_addr)\n{\n    pthread_rwlock_rdlock(&g_ctx.rwlock);\n    if (g_ctx.total_stake == 0 || g_ctx.v_len == 0) {\n        pthread_rwlock_unlock(&g_ctx.rwlock);\n        HC_LOG_ERROR(\"[PoS] no stake available for selection\");\n        return -1;\n    }\n\n    int rc = vrf_elect(&g_ctx, prev_block_hash, out_addr);\n    pthread_rwlock_unlock(&g_ctx.rwlock);\n\n    return rc;\n}\n\n\n/* ------------------------------------------------------------------------- *\n *                        Internal helper functions                          *\n * ------------------------------------------------------------------------- */\n\n/*\n * ensure_capacity()\n * -----------------\n * Grow the validator array if necessary.\n */\nstatic int\nensure_capacity(pos_ctx_t *ctx)\n{\n    if (ctx->v_len < ctx->v_cap)\n        return 0;\n\n    size_t new_cap = ctx->v_cap * 2;\n    validator_entry_t *tmp = realloc(ctx->validators,\n                                     new_cap * sizeof(validator_entry_t));\n    if (!tmp) {\n        perror(\"[PoS] realloc validators\");\n        return -1;\n    }\n    ctx->validators = tmp;\n    ctx->v_cap = new_cap;\n    return 0;\n}\n\n\n/*\n * find_validator()\n * ----------------\n * Return the index of a validator in the array, or ‑1 if not present.\n * Linear search is acceptable for few hundred validators; for larger sets an\n * ordered map should be used (omitted for brevity).\n */\nstatic ssize_t\nfind_validator(pos_ctx_t *ctx, const wallet_addr_t addr)\n{\n    for (size_t i = 0; i < ctx->v_len; ++i) {\n        if (memcmp(ctx->validators[i].address, addr, WALLET_ADDR_LEN) == 0)\n            return (ssize_t)i;\n    }\n    return -1;\n}\n\n\n/*\n * add_validator()\n * ---------------\n * Append a new validator to the table.\n */\nstatic int\nadd_validator(pos_ctx_t *ctx,\n              const wallet_addr_t addr,\n              uint64_t stake)\n{\n    if (ensure_capacity(ctx) != 0)\n        return -1;\n\n    validator_entry_t *v = &ctx->validators[ctx->v_len++];\n    memset(v, 0, sizeof(*v));\n    memcpy(v->address, addr, WALLET_ADDR_LEN);\n    v->stake        = stake;\n    v->locked_until = ctx->current_epoch + POS_MIN_LOCK_EPOCHS;\n    v->jailed       = false;\n\n    HC_LOG_INFO(\"[PoS] new validator %.8s…, stake=%\" PRIu64,\n                addr, stake);\n    return 0;\n}\n\n\n/*\n * vrf_elect()\n * -----------\n * Perform stake-weighted random election using libsodium's crypto_core_ed25519.\n * The VRF simulates a beacon: H = Hash(prev_hash || validator_pub || epoch).\n * Each validator computes H and compares it with a threshold derived from\n * stake/total.  The smallest valid H wins.  For centralised selection (this\n * service) we compute H for all candidates.\n */\nstatic int\nvrf_elect(const pos_ctx_t *ctx,\n          const uint8_t prev_block_hash[crypto_hash_sha256_BYTES],\n          wallet_addr_t out_selected)\n{\n    uint8_t min_hash[crypto_hash_sha256_BYTES];\n    bool    selected = false;\n\n    for (size_t i = 0; i < ctx->v_len; ++i) {\n        const validator_entry_t *v = &ctx->validators[i];\n        if (v->jailed || v->stake == 0)\n            continue;\n\n        /* Beacon: hash(prev_hash | validator_pub | epoch_le) */\n        uint8_t buf[crypto_hash_sha256_BYTES + WALLET_ADDR_LEN + sizeof(uint64_t)];\n        size_t  off = 0;\n        memcpy(buf + off, prev_block_hash, crypto_hash_sha256_BYTES); off += crypto_hash_sha256_BYTES;\n        memcpy(buf + off, v->address, WALLET_ADDR_LEN);               off += WALLET_ADDR_LEN;\n        uint64_t epoch_le = htole64(ctx->current_epoch);\n        memcpy(buf + off, &epoch_le, sizeof(epoch_le));\n\n        uint8_t h[crypto_hash_sha256_BYTES];\n        crypto_hash_sha256(h, buf, sizeof(buf));\n\n        /* Convert leading 16 bytes to a 128-bit integer for comparison */\n        if (!selected || memcmp(h, min_hash, 16) < 0) {\n            memcpy(min_hash, h, sizeof(min_hash));\n            memcpy(out_selected, v->address, WALLET_ADDR_LEN);\n            selected = true;\n        }\n    }\n\n    if (!selected)\n        return -1;\n\n    return 0;\n}\n\n\n/*\n * apply_block_rewards()\n * ---------------------\n * Credit proposer with block reward plus fees, and distribute a portion to\n * delegators (omitted for brevity).\n */\nstatic int\napply_block_rewards(pos_ctx_t *ctx,\n                    const wallet_addr_t proposer,\n                    uint64_t block_fees)\n{\n    static const uint64_t BASE_REWARD = 5 * HC_COINS; /* 5 tokens per block */\n\n    pthread_rwlock_wrlock(&ctx->rwlock);\n    ssize_t idx = find_validator(ctx, proposer);\n    if (idx < 0) {\n        pthread_rwlock_unlock(&ctx->rwlock);\n        return -1;\n    }\n\n    validator_entry_t *v = &ctx->validators[idx];\n    v->rewards += BASE_REWARD + block_fees;\n    pthread_rwlock_unlock(&ctx->rwlock);\n\n    /* Emit reward event */\n    reward_event_t rev = {\n        .validator = {0},\n        .amount    = BASE_REWARD + block_fees\n    };\n    memcpy(rev.validator, proposer, WALLET_ADDR_LEN);\n    event_t ev = {\n        .type    = EVENT_REWARD,\n        .payload = &rev\n    };\n    event_bus_publish(ctx->bus, &ev);\n\n    HC_LOG_DEBUG(\"[PoS] rewarded %.8s… with %\" PRIu64,\n                 proposer, rev.amount);\n    return 0;\n}\n\n\n/*\n * slash_validator()\n * -----------------\n * Slash a validator for misbehaviour by burning a percentage of its stake and\n * jailing it for several epochs.\n */\nstatic int\nslash_validator(pos_ctx_t *ctx,\n                const wallet_addr_t address,\n                const char *reason)\n{\n    pthread_rwlock_wrlock(&ctx->rwlock);\n    ssize_t idx = find_validator(ctx, address);\n    if (idx < 0) {\n        pthread_rwlock_unlock(&ctx->rwlock);\n        return -1;\n    }\n\n    validator_entry_t *v = &ctx->validators[idx];\n    uint64_t penalty = v->stake / POS_SLASH_FRACTION;\n    v->stake -= penalty;\n    v->jailed = true;\n\n    ctx->total_stake -= penalty;\n    pthread_rwlock_unlock(&ctx->rwlock);\n\n    HC_LOG_WARN(\"[PoS] validator %.8s… slashed by %\" PRIu64 \" (%s)\",\n                address, penalty, reason);\n\n    /* Emit slashing event */\n    slash_event_t sev = {\n        .validator = {0},\n        .amount    = penalty,\n        .reason    = {0}\n    };\n    memcpy(sev.validator, address, WALLET_ADDR_LEN);\n    strncpy(sev.reason, reason, sizeof(sev.reason)-1);\n\n    event_t ev = {\n        .type    = EVENT_SLASH,\n        .payload = &sev\n    };\n    event_bus_publish(ctx->bus, &ev);\n\n    return 0;\n}\n", "numLines": 554, "startLine": 1, "totalLines": 554}}

1→/*
     2→ * recipe_composer.c
     3→ *
     4→ * HoloCanvas – Mint-Factory Microservice
     5→ * --------------------------------------
     6→ * Creates an immutable “creative recipe” for a to-be-minted artifact by
     7→ * composing user-submitted fragments (GLSL shader code, audio buffers,
     8→ * arbitrary metadata) into a canonical JSON document. The finalized recipe
     9→ * is hashed (SHA-256) and persisted to durable storage (e.g. roll-up chain,
    10→ * IPFS, Cold-DB) while an event is emitted to the mesh for downstream
    11→ * consumers (LedgerCore, Gallery-Gateway, etc.).
    12→ *
    13→ * This module focuses on the composition, hashing, validation, persistence
    14→ * (filesystem-backed for now), and event-publication stubs.
    15→ *
    16→ * Dependencies:
    17→ *   – OpenSSL libcrypto (SHA-256)
    18→ *   – cJSON             (JSON construction)
    19→ *   – librdkafka        (Kafka producer)       [compile-time option]
    20→ *
    21→ * Compile example:
    22→ *   gcc -Wall -Wextra -O2 \
    23→ *       -DUSE_KAFKA \
    24→ *       recipe_composer.c -lcjson -lcrypto -lpthread -lrdkafka -o recipe_composer
    25→ *
    26→ * Author:  HoloCanvas Core Team
    27→ */
    28→
    29→#include <stdio.h>
    30→#include <stdlib.h>
    31→#include <stdint.h>
    32→#include <stdbool.h>
    33→#include <stdarg.h>
    34→#include <string.h>
    35→#include <time.h>
    36→#include <errno.h>
    37→#include <pthread.h>
    38→#include <sys/stat.h>
    39→
    40→#include <openssl/sha.h>
    41→#include <cjson/cJSON.h>
    42→
    43→#ifdef USE_KAFKA
    44→#include <rdkafka.h>
    45→#endif
    46→
    47→/* ---------- Constants & Macros ------------------------------------------ */
    48→
    49→#define RC_OK                   (0)
    50→#define RC_ERR_GENERIC          (-1)
    51→#define RC_ERR_OOM              (-2)
    52→#define RC_ERR_INVALID_ARG      (-3)
    53→#define RC_ERR_IO               (-4)
    54→#define RC_ERR_JSON             (-5)
    55→#define RC_ERR_STATE            (-6)
    56→
    57→#define UNUSED(x)               (void)(x)
    58→
    59→#define SHA256_HEX_LENGTH       (SHA256_DIGEST_LENGTH * 2)
    60→
    61→/* ---------- Typedefs ---------------------------------------------------- */
    62→
    63→typedef enum {
    64→    FRAG_SHADER,
    65→    FRAG_AUDIO,
    66→    FRAG_METADATA,
    67→    FRAG_UNKNOWN
    68→} fragment_type_e;
    69→
    70→typedef struct {
    71→    fragment_type_e   type;
    72→    char             *id;        /* user-supplied fragment ID */
    73→    char             *content;   /* raw content */
    74→    size_t            content_sz;
    75→} recipe_fragment_t;
    76→
    77→typedef struct {
    78→    char               *artifact_id;
    79→    char               *author_wallet;
    80→    recipe_fragment_t **fragments;
    81→    size_t              frag_count;
    82→    size_t              frag_capacity;
    83→    pthread_mutex_t     lock;
    84→    bool                finalized;
    85→    char                sha256_hex[SHA256_HEX_LENGTH + 1]; /* null-terminated */
    86→} recipe_composer_t;
    87→
    88→/* ---------- Forward Declarations --------------------------------------- */
    89→
    90→static int  rc_log_err(int rc, const char *fmt, ...);
    91→static void rc_free_fragment(recipe_fragment_t *frag);
    92→static int  rc_expand_frag_array(recipe_composer_t *rc);
    93→
    94→/* ---------- Public API -------------------------------------------------- */
    95→
    96→/*
    97→ * rc_create()
    98→ * Initializes a new recipe composer context.
    99→ */
   100→recipe_composer_t *
   101→rc_create(const char *artifact_id, const char *author_wallet)
   102→{
   103→    if (!artifact_id || !author_wallet) {
   104→        rc_log_err(RC_ERR_INVALID_ARG, "artifact_id and author_wallet required");
   105→        return NULL;
   106→    }
   107→
   108→    recipe_composer_t *rc = calloc(1, sizeof(*rc));
   109→    if (!rc) {
   110→        rc_log_err(RC_ERR_OOM, "calloc failed");
   111→        return NULL;
   112→    }
   113→
   114→    rc->artifact_id   = strdup(artifact_id);
   115→    rc->author_wallet = strdup(author_wallet);
   116→    rc->frag_capacity = 8; /* start with modest capacity */
   117→    rc->fragments     = calloc(rc->frag_capacity, sizeof(recipe_fragment_t *));
   118→    if (!rc->artifact_id || !rc->author_wallet || !rc->fragments) {
   119→        rc_log_err(RC_ERR_OOM, "calloc/strdup failed");
   120→        free(rc->artifact_id);
   121→        free(rc->author_wallet);
   122→        free(rc->fragments);
   123→        free(rc);
   124→        return NULL;
   125→    }
   126→
   127→    pthread_mutex_init(&rc->lock, NULL);
   128→    return rc;
   129→}
   130→
   131→/*
   132→ * rc_destroy()
   133→ * Frees all resources associated with the composer.
   134→ */
   135→void
   136→rc_destroy(recipe_composer_t *rc)
   137→{
   138→    if (!rc) return;
   139→
   140→    for (size_t i = 0; i < rc->frag_count; ++i)
   141→        rc_free_fragment(rc->fragments[i]);
   142→
   143→    free(rc->fragments);
   144→    free(rc->artifact_id);
   145→    free(rc->author_wallet);
   146→    pthread_mutex_destroy(&rc->lock);
   147→    free(rc);
   148→}
   149→
   150→/*
   151→ * rc_add_fragment()
   152→ * Adds a fragment to the recipe. Ownership of `content` is transferred to the
   153→ * composer on success (caller must malloc it).
   154→ */
   155→int
   156→rc_add_fragment(recipe_composer_t *rc,
   157→                fragment_type_e type,
   158→                const char     *fragment_id,
   159→                char           *content,
   160→                size_t          content_sz)
   161→{
   162→    if (!rc || !fragment_id || !content || content_sz == 0)
   163→        return rc_log_err(RC_ERR_INVALID_ARG,
   164→                          "add_fragment() invalid arguments");
   165→
   166→    pthread_mutex_lock(&rc->lock);
   167→
   168→    if (rc->finalized) {
   169→        pthread_mutex_unlock(&rc->lock);
   170→        return rc_log_err(RC_ERR_STATE,
   171→                          "cannot add fragment: recipe already finalized");
   172→    }
   173→
   174→    /* Capacity expansion if needed */
   175→    if (rc->frag_count >= rc->frag_capacity &&
   176→        rc_expand_frag_array(rc) != RC_OK) {
   177→        pthread_mutex_unlock(&rc->lock);
   178→        return rc_log_err(RC_ERR_OOM, "expanding fragment array failed");
   179→    }
   180→
   181→    recipe_fragment_t *frag = calloc(1, sizeof(*frag));
   182→    if (!frag) {
   183→        pthread_mutex_unlock(&rc->lock);
   184→        return rc_log_err(RC_ERR_OOM, "calloc failed");
   185→    }
   186→    frag->type       = type;
   187→    frag->id         = strdup(fragment_id);
   188→    frag->content    = content;       /* take ownership */
   189→    frag->content_sz = content_sz;
   190→
   191→    if (!frag->id) {
   192→        rc_free_fragment(frag);
   193→        pthread_mutex_unlock(&rc->lock);
   194→        return rc_log_err(RC_ERR_OOM, "strdup failed");
   195→    }
   196→
   197→    rc->fragments[rc->frag_count++] = frag;
   198→    pthread_mutex_unlock(&rc->lock);
   199→    return RC_OK;
   200→}
   201→
   202→/*
   203→ * rc_finalize()
   204→ * Assembles JSON, computes SHA-256, persists to disk, and emits Kafka event.
   205→ */
   206→int
   207→rc_finalize(recipe_composer_t *rc,
   208→            const char *storage_path,   /* directory for recipe JSON */
   209→            const char *kafka_topic)    /* optional, NULL to skip */
   210→{
   211→    if (!rc || !storage_path)
   212→        return rc_log_err(RC_ERR_INVALID_ARG, "finalize() invalid arguments");
   213→
   214→    pthread_mutex_lock(&rc->lock);
   215→    if (rc->finalized) {
   216→        pthread_mutex_unlock(&rc->lock);
   217→        return rc_log_err(RC_ERR_STATE, "recipe already finalized");
   218→    }
   219→
   220→    /* -------------------- Build JSON -------------------- */
   221→    cJSON *root = cJSON_CreateObject();
   222→    if (!root) {
   223→        pthread_mutex_unlock(&rc->lock);
   224→        return rc_log_err(RC_ERR_JSON, "failed to create JSON root");
   225→    }
   226→
   227→    cJSON_AddStringToObject(root, "artifact_id", rc->artifact_id);
   228→    cJSON_AddStringToObject(root, "author_wallet", rc->author_wallet);
   229→
   230→    char iso8601[32] = {0};
   231→    time_t now = time(NULL);
   232→    strftime(iso8601, sizeof iso8601, "%Y-%m-%dT%H:%M:%SZ", gmtime(&now));
   233→    cJSON_AddStringToObject(root, "timestamp", iso8601);
   234→
   235→    cJSON *frag_arr = cJSON_AddArrayToObject(root, "fragments");
   236→    if (!frag_arr) {
   237→        cJSON_Delete(root);
   238→        pthread_mutex_unlock(&rc->lock);
   239→        return rc_log_err(RC_ERR_JSON, "failed to create JSON array");
   240→    }
   241→
   242→    for (size_t i = 0; i < rc->frag_count; ++i) {
   243→        recipe_fragment_t *f = rc->fragments[i];
   244→        cJSON *entry = cJSON_CreateObject();
   245→        cJSON_AddStringToObject(entry, "id", f->id);
   246→
   247→        switch (f->type) {
   248→            case FRAG_SHADER:   cJSON_AddStringToObject(entry, "type", "shader");   break;
   249→            case FRAG_AUDIO:    cJSON_AddStringToObject(entry, "type", "audio");    break;
   250→            case FRAG_METADATA: cJSON_AddStringToObject(entry, "type", "metadata"); break;
   251→            default:            cJSON_AddStringToObject(entry, "type", "unknown");  break;
   252→        }
   253→        /* Content is stored as base64 to keep JSON/text-safe */
   254→        char *b64 = NULL;
   255→        size_t b64_len = 0;
   256→        {
   257→            /* --- simplistic Base64 encoding using OpenSSL BIO --- */
   258→            BIO *bio, *b64f;
   259→            BUF_MEM *buffer_ptr = NULL;
   260→
   261→            b64f = BIO_new(BIO_f_base64());
   262→            bio  = BIO_new(BIO_s_mem());
   263→            b64f = BIO_push(b64f, bio);
   264→
   265→            BIO_set_flags(b64f, BIO_FLAGS_BASE64_NO_NL);
   266→            BIO_write(b64f, f->content, (int)f->content_sz);
   267→            BIO_flush(b64f);
   268→            BIO_get_mem_ptr(b64f, &buffer_ptr);
   269→
   270→            b64 = malloc(buffer_ptr->length + 1);
   271→            if (b64) {
   272→                memcpy(b64, buffer_ptr->data, buffer_ptr->length);
   273→                b64[buffer_ptr->length] = 0;
   274→                b64_len = buffer_ptr->length;
   275→            }
   276→            BIO_free_all(b64f);
   277→        }
   278→
   279→        if (!b64) {
   280→            cJSON_Delete(root);
   281→            pthread_mutex_unlock(&rc->lock);
   282→            return rc_log_err(RC_ERR_OOM, "base64 encoding failed");
   283→        }
   284→
   285→        cJSON_AddStringToObject(entry, "content_b64", b64);
   286→        free(b64);
   287→        cJSON_AddItemToArray(frag_arr, entry);
   288→    }
   289→
   290→    char *json_text = cJSON_PrintUnformatted(root);
   291→    cJSON_Delete(root);
   292→    if (!json_text) {
   293→        pthread_mutex_unlock(&rc->lock);
   294→        return rc_log_err(RC_ERR_JSON, "cJSON_Print failed");
   295→    }
   296→
   297→    /* -------------------- Compute SHA-256 -------------------- */
   298→    unsigned char digest[SHA256_DIGEST_LENGTH];
   299→    SHA256((unsigned char *)json_text, strlen(json_text), digest);
   300→
   301→    for (int i = 0; i < SHA256_DIGEST_LENGTH; ++i)
   302→        sprintf(rc->sha256_hex + (i * 2), "%02x", digest[i]);
   303→
   304→    /* -------------------- Persist to storage -------------------- */
   305→    if (mkdir(storage_path, 0755) != 0 && errno != EEXIST) {
   306→        free(json_text);
   307→        pthread_mutex_unlock(&rc->lock);
   308→        return rc_log_err(RC_ERR_IO, "mkdir '%s' failed: %s",
   309→                          storage_path, strerror(errno));
   310→    }
   311→
   312→    char file_path[1024];
   313→    snprintf(file_path, sizeof file_path, "%s/%s.json", storage_path,
   314→             rc->sha256_hex);
   315→
   316→    FILE *fp = fopen(file_path, "w");
   317→    if (!fp) {
   318→        free(json_text);
   319→        pthread_mutex_unlock(&rc->lock);
   320→        return rc_log_err(RC_ERR_IO, "fopen '%s' failed: %s",
   321→                          file_path, strerror(errno));
   322→    }
   323→
   324→    if (fwrite(json_text, 1, strlen(json_text), fp)
   325→        != strlen(json_text)) {
   326→        fclose(fp);
   327→        unlink(file_path);
   328→        free(json_text);
   329→        pthread_mutex_unlock(&rc->lock);
   330→        return rc_log_err(RC_ERR_IO, "fwrite failed");
   331→    }
   332→    fclose(fp);
   333→
   334→    /* -------------------- Emit event -------------------- */
   335→#ifdef USE_KAFKA
   336→    if (kafka_topic) {
   337→        char errstr[512];
   338→        rd_kafka_conf_t *conf = rd_kafka_conf_new();
   339→        rd_kafka_conf_set(conf, "bootstrap.servers", "localhost:9092",
   340→                          errstr, sizeof errstr);
   341→
   342→        rd_kafka_t *rk = rd_kafka_new(RD_KAFKA_PRODUCER, conf,
   343→                                      errstr, sizeof errstr);
   344→        if (!rk) {
   345→            rc_log_err(RC_ERR_GENERIC, "rd_kafka_new failed: %s", errstr);
   346→        } else {
   347→            rd_kafka_resp_err_t rerr;
   348→            rerr = rd_kafka_producev(
   349→                rk,
   350→                RD_KAFKA_V_TOPIC(kafka_topic),
   351→                RD_KAFKA_V_VALUE(rc->sha256_hex, SHA256_HEX_LENGTH),
   352→                RD_KAFKA_V_END);
   353→            if (rerr)
   354→                rc_log_err(RC_ERR_GENERIC, "kafka produce failed: %s",
   355→                           rd_kafka_err2str(rerr));
   356→
   357→            rd_kafka_flush(rk, 3000);
   358→            rd_kafka_destroy(rk);
   359→        }
   360→    }
   361→#else
   362→    UNUSED(kafka_topic);
   363→#endif
   364→
   365→    /* mark finalized */
   366→    rc->finalized = true;
   367→    free(json_text);
   368→    pthread_mutex_unlock(&rc->lock);
   369→    return RC_OK;
   370→}
   371→
   372→/*
   373→ * rc_get_sha256()
   374→ * Returns the hex-encoded SHA-256 hash after finalize().
   375→ */
   376→const char *
   377→rc_get_sha256(recipe_composer_t *rc)
   378→{
   379→    if (!rc || !rc->finalized) return NULL;
   380→    return rc->sha256_hex;
   381→}
   382→
   383→/* ---------- Internal Helpers ------------------------------------------- */
   384→
   385→static int
   386→rc_log_err(int rc, const char *fmt, ...)
   387→{
   388→    va_list ap;
   389→    va_start(ap, fmt);
   390→    fprintf(stderr, "[recipe_composer] ERROR: ");
   391→    vfprintf(stderr, fmt, ap);
   392→    fprintf(stderr, "\n");
   393→    va_end(ap);
   394→    return rc;
   395→}
   396→
   397→static void
   398→rc_free_fragment(recipe_fragment_t *frag)
   399→{
   400→    if (!frag) return;
   401→    free(frag->id);
   402→    free(frag->content);
   403→    free(frag);
   404→}
   405→
   406→static int
   407→rc_expand_frag_array(recipe_composer_t *rc)
   408→{
   409→    size_t new_cap = rc->frag_capacity * 2;
   410→    recipe_fragment_t **tmp =
   411→        realloc(rc->fragments, new_cap * sizeof(recipe_fragment_t *));
   412→    if (!tmp) return RC_ERR_OOM;
   413→    rc->fragments = tmp;
   414→    rc->frag_capacity = new_cap;
   415→    return RC_OK;
   416→}
   417→
   418→/* ---------- Test Harness (optional) ------------------------------------ */
   419→#ifdef RC_UNIT_TEST
   420→
   421→static char *slurp_file(const char *path, size_t *out_sz);
   422→
   423→int main(void)
   424→{
   425→    recipe_composer_t *rc = rc_create("artifact_123", "0xDEADBEEF");
   426→    if (!rc) return EXIT_FAILURE;
   427→
   428→    /* add dummy shader fragment */
   429→    size_t sz = 0;
